import networkx as nx
from typing import List, Dict, Tuple
import heapq
from collections import defaultdict
import math

def search_algorithm(src: str, dsts: List[str], G: nx.DiGraph, num_partitions: int) -> BroadCastTopology:
    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    # Clean graph: remove incoming to source and self-loops
    H = G.copy()
    H.remove_edges_from(list(H.in_edges(src)) + list(nx.selfloop_edges(H)))

    # Get provider prefix
    def get_provider(node: str) -> str:
        if node.startswith("aws:"):
            return "aws"
        elif node.startswith("azure:"):
            return "azure"
        elif node.startswith("gcp:"):
            return "gcp"
        return "other"

    # Precompute all-pairs shortest paths within providers for hub selection
    provider_nodes = defaultdict(list)
    for node in H.nodes():
        provider_nodes[get_provider(node)].append(node)

    # Compute shortest paths from src to all nodes
    src_paths = {}
    src_costs = {}
    for node in H.nodes():
        if node == src:
            src_paths[node] = [src]
            src_costs[node] = 0.0
            continue
        try:
            path = nx.dijkstra_path(H, src, node, weight='cost')
            src_paths[node] = path
            cost = 0.0
            for i in range(len(path)-1):
                cost += H[path[i]][path[i+1]]['cost']
            src_costs[node] = cost
        except:
            src_paths[node] = []
            src_costs[node] = float('inf')

    # Find best hub for each provider using centrality measure
    provider_hubs = {}
    for provider, nodes in provider_nodes.items():
        dests_in_provider = [d for d in dsts if get_provider(d) == provider]
        if not dests_in_provider:
            continue

        best_score = float('inf')
        best_hub = None

        # Consider nodes that are reachable from source
        candidates = [n for n in nodes if src_costs[n] < float('inf')]
        if not candidates:
            continue

        # Precompute intra-provider distances for candidate evaluation
        intra_dist = {}
        for cand in candidates[:30]:  # Limit for speed
            # Compute average distance to destinations in same provider
            total_dist = 0.0
            reachable_count = 0
            for dst in dests_in_provider:
                if dst == cand:
                    reachable_count += 1
                    continue
                try:
                    dist = nx.dijkstra_path_length(H, cand, dst, weight='cost')
                    total_dist += dist
                    reachable_count += 1
                except:
                    continue

            if reachable_count == 0:
                continue

            avg_dist = total_dist / reachable_count
            # Score combines distance from source and to destinations
            score = 0.3 * src_costs[cand] + 0.7 * avg_dist

            if score < best_score:
                best_score = score
                best_hub = cand

        if best_hub:
            provider_hubs[provider] = best_hub

    # For each destination, generate diverse path candidates
    dst_candidates = {}
    for dst in dsts:
        candidates = []

        # 1. Direct shortest path
        if src_paths[dst]:
            candidates.append((src_paths[dst], src_costs[dst], 0))

        # 2. Via same-provider hub
        dst_provider = get_provider(dst)
        if dst_provider in provider_hubs and provider_hubs[dst_provider] != dst:
            hub = provider_hubs[dst_provider]
            if src_paths[hub]:
                try:
                    hub_to_dst = nx.dijkstra_path(H, hub, dst, weight='cost')
                    # Combine paths
                    combined_path = src_paths[hub][:-1] + hub_to_dst
                    cost = 0.0
                    for i in range(len(combined_path)-1):
                        cost += H[combined_path[i]][combined_path[i+1]]['cost']
                    candidates.append((combined_path, cost, 1))
                except:
                    pass

        # 3. Via cross-provider hubs (for diversity)
        for other_provider, hub in provider_hubs.items():
            if other_provider == dst_provider or hub == dst:
                continue
            if src_paths[hub]:
                try:
                    hub_to_dst = nx.dijkstra_path(H, hub, dst, weight='cost')
                    combined_path = src_paths[hub][:-1] + hub_to_dst
                    cost = 0.0
                    for i in range(len(combined_path)-1):
                        cost += H[combined_path[i]][combined_path[i+1]]['cost']
                    candidates.append((combined_path, cost, 2))
                except:
                    pass

        # 4. Generate alternative paths by perturbing the graph
        if candidates:
            best_path = min(candidates, key=lambda x: x[1])[0]
            # Try removing edges from best path to find alternatives
            for i in range(len(best_path)-1):
                u, v = best_path[i], best_path[i+1]
                if not H.has_edge(u, v):
                    continue
                edge_data = H[u][v]
                H.remove_edge(u, v)
                try:
                    alt_path = nx.dijkstra_path(H, src, dst, weight='cost')
                    alt_cost = 0.0
                    for j in range(len(alt_path)-1):
                        alt_cost += H[alt_path[j]][alt_path[j+1]]['cost']
                    if alt_path != best_path:
                        candidates.append((alt_path, alt_cost, 3))
                except:
                    pass
                H.add_edge(u, v, **edge_data)

        # 5. Fallback: BFS path
        if not candidates:
            try:
                bfs_path = nx.shortest_path(H, src, dst)
                cost = sum(H[bfs_path[i]][bfs_path[i+1]]['cost'] for i in range(len(bfs_path)-1))
                candidates.append((bfs_path, cost, 4))
            except:
                continue

        # Deduplicate and keep best candidates
        seen = set()
        unique = []
        for path, cost, typ in candidates:
            key = tuple(path)
            if key not in seen:
                seen.add(key)
                unique.append((path, cost, typ))
        unique.sort(key=lambda x: x[1])
        dst_candidates[dst] = unique[:min(6, len(unique))]

    # Edge-usage aware partition assignment with simulated annealing
    edge_usage = defaultdict(int)
    assignments = {}

    # Initial assignment: cheapest path for all partitions
    for dst in dsts:
        if dst in dst_candidates and dst_candidates[dst]:
            cheapest_path = dst_candidates[dst][0][0]
            assignments[dst] = [0] * num_partitions
            for p in range(num_partitions):
                for i in range(len(cheapest_path)-1):
                    edge = (cheapest_path[i], cheapest_path[i+1])
                    edge_usage[edge] += 1

    # Simulated annealing for better edge sharing
    import random
    temperature = 1.0
    cooling_rate = 0.95
    iterations = 50

    for iter in range(iterations):
        for dst in dsts:
            if dst not in dst_candidates or len(dst_candidates[dst]) < 2:
                continue

            for p in range(num_partitions):
                current_idx = assignments[dst][p]
                current_path, current_cost, _ = dst_candidates[dst][current_idx]

                # Calculate current edge sharing contribution
                current_share = 0
                for i in range(len(current_path)-1):
                    edge = (current_path[i], current_path[i+1])
                    current_share += edge_usage[edge] - 1  # exclude self

                # Try random alternative
                alt_idx = random.randrange(len(dst_candidates[dst]))
                if alt_idx == current_idx:
                    continue

                alt_path, alt_cost, _ = dst_candidates[dst][alt_idx]

                # Calculate alternative edge sharing
                alt_share = 0
                for i in range(len(alt_path)-1):
                    edge = (alt_path[i], alt_path[i+1])
                    alt_share += edge_usage[edge]

                # Calculate delta
                delta_share = alt_share - current_share
                delta_cost = alt_cost - current_cost

                # Combined improvement metric (favor sharing, penalize cost increase)
                improvement = delta_share - 0.02 * delta_cost * num_partitions

                # Accept if improvement > 0 or with probability exp(improvement/temperature)
                if improvement > 0 or random.random() < math.exp(improvement / temperature):
                    # Update edge usage
                    for i in range(len(current_path)-1):
                        edge = (current_path[i], current_path[i+1])
                        edge_usage[edge] -= 1

                    for i in range(len(alt_path)-1):
                        edge = (alt_path[i], alt_path[i+1])
                        edge_usage[edge] += 1

                    assignments[dst][p] = alt_idx

        temperature *= cooling_rate

    # Final pass: greedy local improvement
    for _ in range(20):
        improved = False
        for dst in dsts:
            if dst not in dst_candidates or len(dst_candidates[dst]) < 2:
                continue

            for p in range(num_partitions):
                current_idx = assignments[dst][p]
                current_path, current_cost, _ = dst_candidates[dst][current_idx]

                # Find best alternative
                best_idx = current_idx
                best_gain = 0

                for alt_idx, (alt_path, alt_cost, _) in enumerate(dst_candidates[dst]):
                    if alt_idx == current_idx:
                        continue

                    # Calculate gain
                    current_share = 0
                    for i in range(len(current_path)-1):
                        edge = (current_path[i], current_path[i+1])
                        current_share += edge_usage[edge] - 1

                    alt_share = 0
                    for i in range(len(alt_path)-1):
                        edge = (alt_path[i], alt_path[i+1])
                        alt_share += edge_usage[edge]

                    gain = (alt_share - current_share) - 0.01 * (alt_cost - current_cost) * num_partitions

                    if gain > best_gain:
                        best_gain = gain
                        best_idx = alt_idx

                if best_idx != current_idx and best_gain > 0:
                    improved = True
                    # Update edge usage
                    for i in range(len(current_path)-1):
                        edge = (current_path[i], current_path[i+1])
                        edge_usage[edge] -= 1

                    new_path = dst_candidates[dst][best_idx][0]
                    for i in range(len(new_path)-1):
                        edge = (new_path[i], new_path[i+1])
                        edge_usage[edge] += 1

                    assignments[dst][p] = best_idx

        if not improved:
            break

    # Build final topology
    for dst in dsts:
        if dst not in assignments or dst not in dst_candidates:
            # Fallback to direct path if available
            if src_paths.get(dst):
                path = src_paths[dst]
                for p in range(num_partitions):
                    for i in range(len(path)-1):
                        u, v = path[i], path[i+1]
                        if G.has_edge(u, v):
                            bc_topology.append_dst_partition_path(dst, p, [u, v, G[u][v]])
            continue

        for p in range(num_partitions):
            path_idx = assignments[dst][p]
            if path_idx < len(dst_candidates[dst]):
                path = dst_candidates[dst][path_idx][0]
                for i in range(len(path)-1):
                    u, v = path[i], path[i+1]
                    if G.has_edge(u, v):
                        bc_topology.append_dst_partition_path(dst, p, [u, v, G[u][v]])

    return bc_topology

