import networkx as nx
from typing import List, Dict, Tuple
from collections import defaultdict
import heapq

def search_algorithm(src: str, dsts: List[str], G: nx.DiGraph, num_partitions: int) -> BroadCastTopology:
    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    # Remove source from destinations to avoid self-loops
    destinations = [d for d in dsts if d != src]

    # Precompute all-pairs shortest paths for fallback
    shortest_paths = {}
    for dst in destinations:
        try:
            shortest_paths[dst] = nx.dijkstra_path(G, src, dst, weight='cost')
        except:
            shortest_paths[dst] = None

    # For each destination, get diverse paths
    all_paths_per_dst = {}

    for dst in destinations:
        paths = []

        # Add the shortest path
        if shortest_paths[dst]:
            paths.append(shortest_paths[dst])

        # Add alternative paths using k-shortest paths 
        k = min(5, num_partitions * 2)
        try:
            path_gen = nx.shortest_simple_paths(G, src, dst, weight='cost')
            for i, path in enumerate(path_gen):
                if i >= k:
                    break
                if path not in paths:
                    paths.append(path)
        except:
            pass

        # If no alternative paths, try to generate some
        if len(paths) < num_partitions:
            # Generate some paths through intermediate nodes
            intermediate_nodes = list(G.nodes())
            for node in intermediate_nodes[:10]:  # Limit intermediate nodes
                if node != src and node != dst:
                    try:
                        path1 = nx.dijkstra_path(G, src, node, weight='cost')
                        path2 = nx.dijkstra_path(G, node, dst, weight='cost')
                        combined = path1[:-1] + path2
                        if combined not in paths:
                            paths.append(combined)
                        if len(paths) >= num_partitions:
                            break
                    except:
                        continue

        # Keep at least one path
        if not paths:
            paths = [[src, dst]] if G.has_edge(src, dst) else [[src]]

        all_paths_per_dst[dst] = paths[:num_partitions]

    # Greedily assign paths to minimize total cost with edge reuse
    edge_usage = defaultdict(int)
    assignments = {}

    # For each destination, assign partitions
    for dst in destinations:
        assignments[dst] = []
        paths = all_paths_per_dst[dst]

        # Initialize with best paths
        for p in range(num_partitions):
            path_idx = p % len(paths)
            assignments[dst].append(path_idx)

            # Update edge usage for initial assignment
            path = paths[path_idx]
            for i in range(len(path) - 1):
                edge = (path[i], path[i+1])
                edge_usage[edge] += 1

    # Refinement: try to improve assignments
    for iteration in range(3):
        improved = False
        for dst in destinations:
            for p in range(num_partitions):
                current_idx = assignments[dst][p]
                current_path = all_paths_per_dst[dst][current_idx]

                # Remove current path from edge usage
                for i in range(len(current_path) - 1):
                    edge = (current_path[i], current_path[i+1])
                    edge_usage[edge] -= 1

                # Find better path
                best_idx = current_idx
                best_score = -float('inf')

                # Calculate reuse score for all candidate paths
                for idx, path in enumerate(all_paths_per_dst[dst]):
                    score = 0
                    for i in range(len(path) - 1):
                        edge = (path[i], path[i+1])
                        score += edge_usage[edge]

                    # Prefer reuse over cost (with small cost penalty)
                    cost = sum(G[path[i]][path[i+1]]['cost'] for i in range(len(path) - 1))
                    final_score = score - 0.01 * cost

                    if final_score > best_score:
                        best_score = final_score
                        best_idx = idx

                if best_idx != current_idx:
                    improved = True
                    assignments[dst][p] = best_idx

                # Update edge usage
                new_path = all_paths_per_dst[dst][best_idx]
                for i in range(len(new_path) - 1):
                    edge = (new_path[i], new_path[i+1])
                    edge_usage[edge] += 1

        if not improved:
            break

    # Build the final topology
    for dst in destinations:
        for p in range(num_partitions):
            path_idx = assignments[dst][p]
            path = all_paths_per_dst[dst][path_idx]

            for i in range(len(path) - 1):
                u, v = path[i], path[i+1]
                if G.has_edge(u, v):
                    bc_topology.append_dst_partition_path(dst, p, [u, v, G[u][v]])

    return bc_topology

import networkx as nx
from typing import List, Dict, Tuple, Set
import heapq
from collections import defaultdict

def search_algorithm(src: str, dsts: List[str], G: nx.DiGraph, num_partitions: int) -> BroadCastTopology:
    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    # Remove incoming edges to source and self-loops
    H = G.copy()
    H.remove_edges_from(list(H.in_edges(src)) + list(nx.selfloop_edges(H)))

    # Helper to get cloud provider
    def get_provider(node: str) -> str:
        if node.startswith("aws:"):
            return "aws"
        elif node.startswith("azure:"):
            return "azure"
        elif node.startswith("gcp:"):
            return "gcp"
        return "other"

    # Compute shortest paths from source to all nodes
    src_paths = {}
    src_costs = {}
    for node in H.nodes():
        if node == src:
            src_paths[node] = [src]
            src_costs[node] = 0.0
            continue
        try:
            path = nx.dijkstra_path(H, src, node, weight='cost')
            src_paths[node] = path
            cost = 0.0
            for i in range(len(path)-1):
                cost += H[path[i]][path[i+1]]['cost']
            src_costs[node] = cost
        except:
            src_paths[node] = []
            src_costs[node] = float('inf')

    # Group destinations by provider
    provider_dests = defaultdict(list)
    for dst in dsts:
        provider_dests[get_provider(dst)].append(dst)

    # Find best hub per provider (lowest average cost to destinations in that provider)
    provider_hubs = {}
    for provider, dests in provider_dests.items():
        if not dests:
            continue

        candidate_nodes = [n for n in H.nodes() if get_provider(n) == provider]
        if not candidate_nodes:
            continue

        best_score = float('inf')
        best_hub = None

        for cand in candidate_nodes[:25]:  # Limit candidates for speed
            if src_costs[cand] == float('inf'):
                continue

            total_cost = 0.0
            reachable = 0
            for dst in dests:
                if dst == cand:
                    reachable += 1
                    continue
                try:
                    cost = nx.dijkstra_path_length(H, cand, dst, weight='cost')
                    total_cost += cost
                    reachable += 1
                except:
                    continue

            if reachable == 0:
                continue

            avg_cost = total_cost / reachable
            # Combined score favors hubs close to source and close to destinations
            score = src_costs[cand] * 0.4 + avg_cost * 0.6

            if score < best_score:
                best_score = score
                best_hub = cand

        if best_hub:
            provider_hubs[provider] = best_hub

    # For each destination, collect diverse path options
    dst_options = defaultdict(list)

    for dst in dsts:
        # Option 1: Direct path
        if src_paths[dst]:
            dst_options[dst].append((src_paths[dst], src_costs[dst], 'direct'))

        # Option 2: Via same-provider hub
        provider = get_provider(dst)
        if provider in provider_hubs and provider_hubs[provider] != dst:
            hub = provider_hubs[provider]
            if src_paths[hub]:
                try:
                    hub_to_dst = nx.dijkstra_path(H, hub, dst, weight='cost')
                    # Combine paths
                    if src_paths[hub][-1] == hub_to_dst[0]:
                        path = src_paths[hub] + hub_to_dst[1:]
                    else:
                        path = src_paths[hub] + hub_to_dst
                    cost = 0.0
                    for i in range(len(path)-1):
                        cost += H[path[i]][path[i+1]]['cost']
                    dst_options[dst].append((path, cost, 'same_provider'))
                except:
                    pass

        # Option 3: Via cross-provider hubs
        for other_provider, hub in provider_hubs.items():
            if other_provider == provider or hub == dst:
                continue
            if src_paths[hub]:
                try:
                    hub_to_dst = nx.dijkstra_path(H, hub, dst, weight='cost')
                    if src_paths[hub][-1] == hub_to_dst[0]:
                        path = src_paths[hub] + hub_to_dst[1:]
                    else:
                        path = src_paths[hub] + hub_to_dst
                    cost = 0.0
                    for i in range(len(path)-1):
                        cost += H[path[i]][path[i+1]]['cost']
                    dst_options[dst].append((path, cost, f'cross_{other_provider}'))
                except:
                    pass

        # Sort by cost and keep top 5
        dst_options[dst].sort(key=lambda x: x[1])
        dst_options[dst] = dst_options[dst][:5]

    # Ensure every destination has at least one path
    for dst in dsts:
        if not dst_options[dst]:
            # BFS fallback
            try:
                path = nx.shortest_path(H, src, dst)
                cost = sum(H[path[i]][path[i+1]]['cost'] for i in range(len(path)-1))
                dst_options[dst].append((path, cost, 'fallback'))
            except:
                # Last resort: direct edge if exists
                if H.has_edge(src, dst):
                    dst_options[dst].append(([src, dst], H[src][dst]['cost'], 'direct_edge'))

    # Edge-usage aware partition assignment
    edge_usage = defaultdict(int)
    assignments = {}

    # Initial assignment: cheapest path for all partitions
    for dst in dsts:
        if dst_options[dst]:
            cheapest_path = dst_options[dst][0][0]
            assignments[dst] = [0] * num_partitions
            for p in range(num_partitions):
                for i in range(len(cheapest_path)-1):
                    edge = (cheapest_path[i], cheapest_path[i+1])
                    edge_usage[edge] += 1

    # Greedy improvement: reassign partitions to increase edge sharing
    for _ in range(30):
        improved = False

        for dst in dsts:
            if len(dst_options[dst]) < 2:
                continue

            # Evaluate each partition
            for p in range(num_partitions):
                current_idx = assignments[dst][p]
                current_path = dst_options[dst][current_idx][0]
                current_cost = dst_options[dst][current_idx][1]

                # Calculate current edge sharing (excluding this partition)
                current_shared = 0
                for i in range(len(current_path)-1):
                    edge = (current_path[i], current_path[i+1])
                    current_shared += edge_usage[edge] - 1

                best_idx = current_idx
                best_gain = 0.0

                for alt_idx, (alt_path, alt_cost, _) in enumerate(dst_options[dst]):
                    if alt_idx == current_idx:
                        continue

                    # Calculate potential sharing
                    potential_shared = 0
                    for i in range(len(alt_path)-1):
                        edge = (alt_path[i], alt_path[i+1])
                        potential_shared += edge_usage[edge]  # current usage

                    # Gain = increased sharing - cost increase penalty
                    gain = (potential_shared - current_shared) - 0.05 * (alt_cost - current_cost)

                    if gain > best_gain:
                        best_gain = gain
                        best_idx = alt_idx

                if best_idx != current_idx and best_gain > 0:
                    improved = True
                    # Update edge usage
                    for i in range(len(current_path)-1):
                        edge = (current_path[i], current_path[i+1])
                        edge_usage[edge] -= 1

                    new_path = dst_options[dst][best_idx][0]
                    for i in range(len(new_path)-1):
                        edge = (new_path[i], new_path[i+1])
                        edge_usage[edge] += 1

                    assignments[dst][p] = best_idx

        if not improved:
            break

    # Build final topology
    for dst in dsts:
        if dst not in assignments:
            # Fallback: use cheapest path for all partitions
            if dst_options[dst]:
                path = dst_options[dst][0][0]
                for p in range(num_partitions):
                    for i in range(len(path)-1):
                        u, v = path[i], path[i+1]
                        if G.has_edge(u, v):
                            bc_topology.append_dst_partition_path(dst, p, [u, v, G[u][v]])
            continue

        for p in range(num_partitions):
            path_idx = assignments[dst][p]
            if path_idx < len(dst_options[dst]):
                path = dst_options[dst][path_idx][0]
                for i in range(len(path)-1):
                    u, v = path[i], path[i+1]
                    if G.has_edge(u, v):
                        bc_topology.append_dst_partition_path(dst, p, [u, v, G[u][v]])

    return bc_topology

import networkx as nx
from typing import List, Dict, Tuple, Set
import heapq
from collections import defaultdict

def search_algorithm(src: str, dsts: List[str], G: nx.DiGraph, num_partitions: int) -> BroadCastTopology:
    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    # Precompute shortest paths by cost for all destinations
    shortest_paths = {}
    shortest_costs = {}
    for dst in dsts:
        try:
            path = nx.dijkstra_path(G, src, dst, weight='cost')
            shortest_paths[dst] = path
            cost = 0
            for i in range(len(path) - 1):
                cost += G[path[i]][path[i+1]]['cost']
            shortest_costs[dst] = cost
        except:
            shortest_paths[dst] = []
            shortest_costs[dst] = float('inf')

    # Find candidate hub nodes (nodes with high out-degree and low average cost to destinations)
    candidate_hubs = []
    for node in G.nodes():
        if node == src:
            continue
        # Compute average cost from this node to all reachable destinations
        total_cost = 0
        reachable = 0
        for dst in dsts:
            if dst == node:
                continue
            try:
                cost = nx.dijkstra_path_length(G, node, dst, weight='cost')
                total_cost += cost
                reachable += 1
            except:
                continue
        if reachable > 0:
            avg_cost = total_cost / reachable
            out_degree = G.out_degree(node)
            # Higher out-degree and lower average cost are better
            score = out_degree / (avg_cost + 1)
            candidate_hubs.append((score, node))

    candidate_hubs.sort(reverse=True)
    hub_candidates = [node for _, node in candidate_hubs[:50]]  # Consider top 50 candidates

    # For each destination, collect multiple path options
    dst_path_options = {}

    for dst in dsts:
        if dst == src:
            dst_path_options[dst] = [([src], 0)]
            continue

        path_options = []

        # 1. Direct shortest path
        if shortest_paths[dst]:
            path_options.append((shortest_paths[dst], shortest_costs[dst]))

        # 2. Paths via hub candidates
        for hub in hub_candidates:
            if hub == dst or hub == src:
                continue
            try:
                path1 = nx.dijkstra_path(G, src, hub, weight='cost')
                path2 = nx.dijkstra_path(G, hub, dst, weight='cost')
                combined_path = path1 + path2[1:]
                cost = 0
                for i in range(len(combined_path) - 1):
                    cost += G[combined_path[i]][combined_path[i+1]]['cost']

                # Add if significantly different from existing paths
                is_similar = False
                for existing_path, _ in path_options:
                    if len(set(existing_path) & set(combined_path)) > max(2, len(existing_path) * 0.7):
                        is_similar = True
                        break

                if not is_similar:
                    path_options.append((combined_path, cost))

                if len(path_options) >= 20:  # Limit number of options per destination
                    break
            except:
                continue

        # 3. Try to find alternative paths by removing edges from shortest path
        if shortest_paths[dst] and len(shortest_paths[dst]) > 2:
            original_path = shortest_paths[dst]
            for i in range(len(original_path) - 1):
                # Temporarily remove this edge
                edge_data = G[original_path[i]][original_path[i+1]]
                G.remove_edge(original_path[i], original_path[i+1])
                try:
                    alt_path = nx.dijkstra_path(G, src, dst, weight='cost')
                    alt_cost = 0
                    for j in range(len(alt_path) - 1):
                        alt_cost += G[alt_path[j]][alt_path[j+1]]['cost']

                    # Check if this path is different
                    if set(alt_path) != set(original_path):
                        path_options.append((alt_path, alt_cost))
                except:
                    pass
                # Restore edge
                G.add_edge(original_path[i], original_path[i+1], **edge_data)

        # 4. Fallback: try BFS path if we still don't have enough options
        if len(path_options) < 2:
            try:
                bfs_path = nx.shortest_path(G, src, dst)
                if bfs_path not in [p for p, _ in path_options]:
                    cost = 0
                    for i in range(len(bfs_path) - 1):
                        cost += G[bfs_path[i]][bfs_path[i+1]]['cost']
                    path_options.append((bfs_path, cost))
            except:
                pass

        dst_path_options[dst] = path_options

    # Assign partitions to minimize total cost with edge reuse
    edge_usage = defaultdict(int)  # Count how many times each edge is used

    for dst in dsts:
        if dst not in dst_path_options or not dst_path_options[dst]:
            continue

        # Sort paths by base cost
        paths = dst_path_options[dst]

        for partition in range(num_partitions):
            # For each partition, choose the path that minimizes additional cost
            # considering edge reuse
            best_path = None
            best_additional_cost = float('inf')

            for path, base_cost in paths:
                additional_cost = 0
                for i in range(len(path) - 1):
                    u, v = path[i], path[i+1]
                    # If edge is already heavily used, it doesn't add much additional cost
                    # But we still want to account for its base cost
                    if edge_usage[(u, v)] > 0:
                        additional_cost += G[u][v]['cost'] * (1.0 / (edge_usage[(u, v)] + 1))
                    else:
                        additional_cost += G[u][v]['cost']

                if additional_cost < best_additional_cost:
                    best_additional_cost = additional_cost
                    best_path = path

            if best_path:
                # Add the chosen path
                for i in range(len(best_path) - 1):
                    s, t = best_path[i], best_path[i+1]
                    bc_topology.append_dst_partition_path(dst, partition, [s, t, G[s][t]])
                    edge_usage[(s, t)] += 1

    return bc_topology

