def search_algorithm(src: str, dsts: List[str], G: nx.DiGraph, num_partitions: int) -> BroadCastTopology:
    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    # Remove self and destinations that are source
    destinations = [d for d in dsts if d != src]
    if not destinations:
        return bc_topology

    # Precompute shortest paths from source to all nodes
    all_nodes = list(G.nodes())
    cost_to = {}
    path_to = {}

    for node in all_nodes:
        if node == src:
            cost_to[node] = 0.0
            path_to[node] = [src]
            continue
        try:
            path = nx.dijkstra_path(G, src, node, weight='cost')
            cost = sum(G[path[i]][path[i+1]]['cost'] for i in range(len(path)-1))
            cost_to[node] = cost
            path_to[node] = path
        except:
            cost_to[node] = float('inf')
            path_to[node] = []

    # Group destinations by cloud provider
    def get_provider(node: str) -> str:
        if node.startswith("aws:"):
            return "aws"
        elif node.startswith("azure:"):
            return "azure"
        elif node.startswith("gcp:"):
            return "gcp"
        return "unknown"

    provider_dests = defaultdict(list)
    for dst in destinations:
        provider_dests[get_provider(dst)].append(dst)

    # Find best hub for each provider (cheapest to reach from source)
    provider_hub = {}
    for provider, dest_list in provider_dests.items():
        if not dest_list:
            continue
        best_hub = None
        best_cost = float('inf')
        # Consider all nodes from this provider as potential hubs
        for node in all_nodes:
            if get_provider(node) != provider:
                continue
            if cost_to[node] < best_cost:
                best_cost = cost_to[node]
                best_hub = node
        if best_hub:
            provider_hub[provider] = best_hub

    # For each destination, collect candidate paths
    candidate_paths = defaultdict(list)  # dst -> list of (path, cost)

    for dst in destinations:
        # 1. Direct path from source
        if path_to[dst]:
            candidate_paths[dst].append((path_to[dst], cost_to[dst]))

        # 2. Path via provider hub
        provider = get_provider(dst)
        if provider in provider_hub and provider_hub[provider] != dst:
            hub = provider_hub[provider]
            if path_to[hub]:
                try:
                    hub_to_dst = nx.dijkstra_path(G, hub, dst, weight='cost')
                    hub_cost = sum(G[hub_to_dst[i]][hub_to_dst[i+1]]['cost'] for i in range(len(hub_to_dst)-1))
                    combined = path_to[hub] + hub_to_dst[1:]
                    total_cost = cost_to[hub] + hub_cost
                    candidate_paths[dst].append((combined, total_cost))
                except:
                    pass

        # 3. Paths via other provider hubs (cross-cloud)
        for other_provider, other_hub in provider_hub.items():
            if other_provider == provider or other_hub == dst:
                continue
            if path_to[other_hub]:
                try:
                    hub_to_dst = nx.dijkstra_path(G, other_hub, dst, weight='cost')
                    hub_cost = sum(G[hub_to_dst[i]][hub_to_dst[i+1]]['cost'] for i in range(len(hub_to_dst)-1))
                    combined = path_to[other_hub] + hub_to_dst[1:]
                    total_cost = cost_to[other_hub] + hub_cost
                    candidate_paths[dst].append((combined, total_cost))
                except:
                    pass

        # Sort by cost and keep top 3
        candidate_paths[dst].sort(key=lambda x: x[1])
        candidate_paths[dst] = candidate_paths[dst][:3]

        # Ensure at least one path
        if not candidate_paths[dst]:
            try:
                fallback = nx.shortest_path(G, src, dst)
                candidate_paths[dst].append((fallback, float('inf')))
            except:
                continue

    # Edge usage tracking
    edge_usage = defaultdict(int)

    # First pass: assign all partitions to cheapest path
    assignments = {}
    for dst in destinations:
        if candidate_paths[dst]:
            cheapest_path = candidate_paths[dst][0][0]
            assignments[dst] = cheapest_path
            for i in range(len(cheapest_path)-1):
                edge = (cheapest_path[i], cheapest_path[i+1])
                edge_usage[edge] += num_partitions

    # Iterative improvement: reassign partitions to share edges
    for iteration in range(10):
        improved = False
        for dst in destinations:
            if len(candidate_paths[dst]) < 2:
                continue

            current_path = assignments[dst]
            current_shared = 0
            for i in range(len(current_path)-1):
                edge = (current_path[i], current_path[i+1])
                current_shared += edge_usage[edge] - num_partitions

            # Try alternative paths
            best_path = current_path
            best_gain = 0

            for alt_path, alt_cost in candidate_paths[dst]:
                if alt_path == current_path:
                    continue

                # Estimate sharing gain
                potential_shared = 0
                for i in range(len(alt_path)-1):
                    edge = (alt_path[i], alt_path[i+1])
                    potential_shared += edge_usage[edge]

                gain = potential_shared - current_shared
                # Small penalty for higher cost
                cost_diff = alt_cost - candidate_paths[dst][0][1]
                adjusted_gain = gain - cost_diff * 0.05

                if adjusted_gain > best_gain:
                    best_gain = adjusted_gain
                    best_path = alt_path

            if best_path != current_path and best_gain > 0:
                improved = True
                # Update edge usage
                for i in range(len(current_path)-1):
                    edge = (current_path[i], current_path[i+1])
                    edge_usage[edge] -= num_partitions
                for i in range(len(best_path)-1):
                    edge = (best_path[i], best_path[i+1])
                    edge_usage[edge] += num_partitions
                assignments[dst] = best_path

        if not improved:
            break

    # Build final topology
    for dst in destinations:
        if dst not in assignments:
            continue
        path = assignments[dst]
        for partition in range(num_partitions):
            for i in range(len(path)-1):
                u, v = path[i], path[i+1]
                if G.has_edge(u, v):
                    bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])

    return bc_topology

import networkx as nx
from typing import List, Dict, Tuple
from collections import defaultdict
import heapq

def search_algorithm(src: str, dsts: List[str], G: nx.DiGraph, num_partitions: int) -> BroadCastTopology:
    bc_topology = BroadCastTopology(src, dsts, num_partitions)
    if not dsts:
        return bc_topology

    # Precompute all-pairs shortest paths by cost (limited to relevant nodes)
    relevant_nodes = set(dsts) | {src}
    all_paths = {dst: {} for dst in dsts}

    # Compute shortest paths from source to all destinations
    for dst in dsts:
        try:
            path = nx.dijkstra_path(G, src, dst, weight='cost')
            all_paths[dst][src] = (path, sum(G[path[i]][path[i+1]]['cost'] for i in range(len(path)-1)))
        except:
            all_paths[dst][src] = ([], float('inf'))

    # Compute shortest paths between destinations (for potential sharing)
    for i, d1 in enumerate(dsts):
        for d2 in dsts[i+1:]:
            try:
                path = nx.dijkstra_path(G, d1, d2, weight='cost')
                cost = sum(G[path[i]][path[i+1]]['cost'] for i in range(len(path)-1))
                all_paths[d2][d1] = (path, cost)
                all_paths[d1][d2] = (list(reversed(path)), cost)
            except:
                pass

    # Edge capacity tracking
    edge_capacity_used = defaultdict(int)

    # Helper to calculate path cost with sharing benefit
    def path_cost_with_sharing(path):
        total = 0
        for i in range(len(path)-1):
            u, v = path[i], path[i+1]
            base_cost = G[u][v]['cost']
            # Edges already used get discounted cost
            if edge_capacity_used[(u, v)] > 0:
                total += base_cost * (1.0 / (edge_capacity_used[(u, v)] + 1))
            else:
                total += base_cost
        return total

    # Find Steiner tree approximation for each partition
    for partition in range(num_partitions):
        # Start with minimum spanning tree approximation
        current_nodes = set([src])
        remaining_dsts = set(dsts)
        mst_edges = []

        while remaining_dsts:
            best_cost = float('inf')
            best_edge = None
            best_dst = None

            for u in current_nodes:
                for dst in list(remaining_dsts):
                    if dst in all_paths and u in all_paths[dst]:
                        path, base_cost = all_paths[dst][u]
                        if path and base_cost < best_cost:
                            # Calculate effective cost with current sharing
                            effective_cost = 0
                            for i in range(len(path)-1):
                                p, q = path[i], path[i+1]
                                if edge_capacity_used[(p, q)] > 0:
                                    effective_cost += G[p][q]['cost'] * (1.0 / (edge_capacity_used[(p, q)] + 1))
                                else:
                                    effective_cost += G[p][q]['cost']

                            if effective_cost < best_cost:
                                best_cost = effective_cost
                                best_edge = path
                                best_dst = dst

            if best_edge is None:
                # Fallback: use direct paths
                for dst in remaining_dsts:
                    if src in all_paths[dst]:
                        path, _ = all_paths[dst][src]
                        if path:
                            for i in range(len(path)-1):
                                mst_edges.append((path[i], path[i+1]))
                            current_nodes.add(dst)
                            remaining_dsts.remove(dst)
                            break
                continue

            # Add the best path to MST
            for i in range(len(best_edge)-1):
                mst_edges.append((best_edge[i], best_edge[i+1]))
            current_nodes.add(best_dst)
            remaining_dsts.remove(best_dst)

        # Build paths from MST edges for each destination
        # Create a graph from MST edges
        mst_graph = nx.DiGraph()
        for u, v in mst_edges:
            if G.has_edge(u, v):
                mst_graph.add_edge(u, v)
                mst_graph.add_edge(v, u)

        # For each destination, find path in MST from source
        for dst in dsts:
            if nx.has_path(mst_graph, src, dst):
                path = nx.shortest_path(mst_graph, src, dst)
                for i in range(len(path)-1):
                    u, v = path[i], path[i+1]
                    if G.has_edge(u, v):
                        bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])
                        edge_capacity_used[(u, v)] += 1
            else:
                # Fallback to direct shortest path
                if src in all_paths[dst]:
                    path, _ = all_paths[dst][src]
                    if path:
                        for i in range(len(path)-1):
                            u, v = path[i], path[i+1]
                            bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])
                            edge_capacity_used[(u, v)] += 1

    return bc_topology

import networkx as nx
from typing import List, Dict, Tuple
import heapq
from collections import defaultdict
import math
import random

def search_algorithm(src: str, dsts: List[str], G: nx.DiGraph, num_partitions: int) -> BroadCastTopology:
    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    # Remove self-loops and edges into source for cleaner graph
    H = G.copy()
    H.remove_edges_from(list(H.in_edges(src)) + list(nx.selfloop_edges(H)))

    # Helper to get cloud provider
    def get_provider(node: str) -> str:
        if node.startswith("aws:"):
            return "aws"
        elif node.startswith("azure:"):
            return "azure"
        elif node.startswith("gcp:"):
            return "gcp"
        return "other"

    # Precompute shortest paths from source to all nodes
    src_to_all = {}
    for node in H.nodes():
        if node == src:
            src_to_all[node] = ([src], 0.0)
            continue
        try:
            path = nx.dijkstra_path(H, src, node, weight='cost')
            cost = sum(H[path[i]][path[i+1]]['cost'] for i in range(len(path)-1))
            src_to_all[node] = (path, cost)
        except:
            src_to_all[node] = ([], float('inf'))

    # Precompute shortest paths between all destinations
    dst_to_dst = {}
    for dst1 in dsts:
        for dst2 in dsts:
            if dst1 == dst2:
                continue
            key = (dst1, dst2)
            try:
                path = nx.dijkstra_path(H, dst1, dst2, weight='cost')
                cost = sum(H[path[i]][path[i+1]]['cost'] for i in range(len(path)-1))
                dst_to_dst[key] = (path, cost)
            except:
                dst_to_dst[key] = ([], float('inf'))

    # Identify hub candidates: nodes that are central within their provider
    provider_nodes = defaultdict(list)
    for node in H.nodes():
        provider_nodes[get_provider(node)].append(node)

    # For each provider with destinations, find best hub
    provider_hubs = {}
    for provider, nodes in provider_nodes.items():
        dests_in_provider = [d for d in dsts if get_provider(d) == provider]
        if not dests_in_provider:
            continue

        best_score = float('inf')
        best_hub = None

        # Evaluate candidate hubs
        candidates = [n for n in nodes if src_to_all[n][1] < float('inf')]
        if not candidates:
            continue

        for hub in candidates[:20]:  # Limit for speed
            # Compute average distance to destinations in same provider
            total_dist = 0.0
            reachable = 0
            for dst in dests_in_provider:
                if dst == hub:
                    reachable += 1
                    continue
                try:
                    dist = nx.dijkstra_path_length(H, hub, dst, weight='cost')
                    total_dist += dist
                    reachable += 1
                except:
                    continue

            if reachable == 0:
                continue

            avg_dist = total_dist / reachable
            # Score favors hubs with low source cost and good intra-provider connectivity
            score = 0.4 * src_to_all[hub][1] + 0.6 * avg_dist

            if score < best_score:
                best_score = score
                best_hub = hub

        if best_hub:
            provider_hubs[provider] = best_hub

    # Generate diverse path candidates for each destination
    dst_candidates = {}
    max_candidates = 8

    for dst in dsts:
        candidates = []

        # 1. Direct shortest path
        if src_to_all[dst][0]:
            candidates.append((src_to_all[dst][0], src_to_all[dst][1], "direct"))

        # 2. Via same-provider hub
        dst_provider = get_provider(dst)
        if dst_provider in provider_hubs and provider_hubs[dst_provider] != dst:
            hub = provider_hubs[dst_provider]
            hub_path, hub_cost = src_to_all[hub]
            if hub_path:
                try:
                    hub_to_dst = nx.dijkstra_path(H, hub, dst, weight='cost')
                    combined_path = hub_path[:-1] + hub_to_dst
                    cost = hub_cost + sum(H[hub_to_dst[i]][hub_to_dst[i+1]]['cost'] 
                                         for i in range(len(hub_to_dst)-1))
                    candidates.append((combined_path, cost, "same_provider_hub"))
                except:
                    pass

        # 3. Via cross-provider hubs
        for other_provider, hub in provider_hubs.items():
            if other_provider == dst_provider or hub == dst:
                continue
            hub_path, hub_cost = src_to_all[hub]
            if hub_path:
                try:
                    hub_to_dst = nx.dijkstra_path(H, hub, dst, weight='cost')
                    combined_path = hub_path[:-1] + hub_to_dst
                    cost = hub_cost + sum(H[hub_to_dst[i]][hub_to_dst[i+1]]['cost']
                                         for i in range(len(hub_to_dst)-1))
                    candidates.append((combined_path, cost, "cross_provider_hub"))
                except:
                    pass

        # 4. Via other destinations (relay paths)
        for other_dst in dsts:
            if other_dst == dst:
                continue
            other_path, other_cost = src_to_all[other_dst]
            if other_path:
                key = (other_dst, dst)
                if key in dst_to_dst and dst_to_dst[key][0]:
                    relay_path = dst_to_dst[key][0]
                    combined_path = other_path[:-1] + relay_path
                    cost = other_cost + dst_to_dst[key][1]
                    candidates.append((combined_path, cost, "relay_via_dst"))

        # 5. Alternative paths by edge removal
        if candidates:
            best_path = min(candidates, key=lambda x: x[1])[0]
            for i in range(min(3, len(best_path)-1)):
                u, v = best_path[i], best_path[i+1]
                if not H.has_edge(u, v):
                    continue
                edge_data = H[u][v]
                H.remove_edge(u, v)
                try:
                    alt_path = nx.dijkstra_path(H, src, dst, weight='cost')
                    alt_cost = sum(H[alt_path[j]][alt_path[j+1]]['cost'] 
                                  for j in range(len(alt_path)-1))
                    if alt_path != best_path:
                        candidates.append((alt_path, alt_cost, "alternative"))
                except:
                    pass
                H.add_edge(u, v, **edge_data)

        # Deduplicate and select top candidates
        unique_paths = []
        seen = set()
        for path, cost, typ in candidates:
            path_key = tuple(path)
            if path_key not in seen:
                seen.add(path_key)
                unique_paths.append((path, cost, typ))

        unique_paths.sort(key=lambda x: x[1])
        dst_candidates[dst] = unique_paths[:max_candidates]

    # Initialize partition assignments with cheapest paths
    edge_usage = defaultdict(int)
    assignments = {}

    for dst in dsts:
        if dst_candidates.get(dst):
            cheapest_path = dst_candidates[dst][0][0]
            assignments[dst] = [0] * num_partitions  # All partitions use cheapest path index 0
            for p in range(num_partitions):
                for i in range(len(cheapest_path)-1):
                    edge = (cheapest_path[i], cheapest_path[i+1])
                    edge_usage[edge] += 1

    # Simulated annealing for partition assignment
    temperature = 1.0
    cooling_rate = 0.93
    iterations = 80

    def calculate_total_cost():
        total = 0.0
        for dst in dsts:
            if dst not in assignments:
                continue
            for p in range(num_partitions):
                path_idx = assignments[dst][p]
                if path_idx < len(dst_candidates.get(dst, [])):
                    total += dst_candidates[dst][path_idx][1]
        return total

    current_cost = calculate_total_cost()

    for _ in range(iterations):
        # Randomly pick a destination and partition
        dst = random.choice(dsts)
        if not dst_candidates.get(dst) or len(dst_candidates[dst]) < 2:
            continue

        p = random.randint(0, num_partitions-1)
        old_idx = assignments[dst][p]
        new_idx = random.choice([i for i in range(len(dst_candidates[dst])) if i != old_idx])

        old_path = dst_candidates[dst][old_idx][0]
        new_path = dst_candidates[dst][new_idx][0]

        # Calculate cost delta
        old_path_cost = dst_candidates[dst][old_idx][1]
        new_path_cost = dst_candidates[dst][new_idx][1]
        delta_cost = new_path_cost - old_path_cost

        # Calculate edge sharing impact (positive means more sharing)
        sharing_delta = 0
        for i in range(len(old_path)-1):
            edge = (old_path[i], old_path[i+1])
            sharing_delta -= (edge_usage[edge] - 1)

        for i in range(len(new_path)-1):
            edge = (new_path[i], new_path[i+1])
            sharing_delta += edge_usage[edge]

        # Combined metric favors sharing and penalizes cost increase
        # Weight sharing more heavily as it reduces effective cost
        improvement = sharing_delta * 0.5 - delta_cost * 0.01

        # Accept if improvement > 0 or with probability exp(improvement/temperature)
        if improvement > 0 or random.random() < math.exp(improvement / max(temperature, 0.001)):
            # Update edge usage
            for i in range(len(old_path)-1):
                edge = (old_path[i], old_path[i+1])
                edge_usage[edge] -= 1

            for i in range(len(new_path)-1):
                edge = (new_path[i], new_path[i+1])
                edge_usage[edge] += 1

            assignments[dst][p] = new_idx
            current_cost += delta_cost

        temperature *= cooling_rate

    # Final greedy improvement pass
    for _ in range(30):
        improved = False
        for dst in dsts:
            if not dst_candidates.get(dst) or len(dst_candidates[dst]) < 2:
                continue

            for p in range(num_partitions):
                current_idx = assignments[dst][p]
                current_path = dst_candidates[dst][current_idx][0]
                current_cost_part = dst_candidates[dst][current_idx][1]

                # Find best alternative for this partition
                best_idx = current_idx
                best_gain = 0

                for alt_idx, (alt_path, alt_cost, _) in enumerate(dst_candidates[dst]):
                    if alt_idx == current_idx:
                        continue

                    # Calculate sharing gain
                    current_sharing = 0
                    for i in range(len(current_path)-1):
                        edge = (current_path[i], current_path[i+1])
                        current_sharing += (edge_usage[edge] - 1)

                    alt_sharing = 0
                    for i in range(len(alt_path)-1):
                        edge = (alt_path[i], alt_path[i+1])
                        alt_sharing += edge_usage[edge]

                    sharing_gain = alt_sharing - current_sharing
                    cost_delta = alt_cost - current_cost_part

                    gain = sharing_gain * 0.7 - cost_delta * 0.3

                    if gain > best_gain:
                        best_gain = gain
                        best_idx = alt_idx

                if best_idx != current_idx and best_gain > 0:
                    # Update
                    new_path = dst_candidates[dst][best_idx][0]
                    for i in range(len(current_path)-1):
                        edge = (current_path[i], current_path[i+1])
                        edge_usage[edge] -= 1

                    for i in range(len(new_path)-1):
                        edge = (new_path[i], new_path[i+1])
                        edge_usage[edge] += 1

                    assignments[dst][p] = best_idx
                    improved = True

        if not improved:
            break

    # Build final topology
    for dst in dsts:
        if dst not in assignments:
            # Fallback to direct path
            if src_to_all[dst][0]:
                path = src_to_all[dst][0]
                for p in range(num_partitions):
                    for i in range(len(path)-1):
                        u, v = path[i], path[i+1]
                        if G.has_edge(u, v):
                            bc_topology.append_dst_partition_path(dst, p, [u, v, G[u][v]])
            continue

        for p in range(num_partitions):
            path_idx = assignments[dst][p]
            if path_idx < len(dst_candidates[dst]):
                path = dst_candidates[dst][path_idx][0]
                for i in range(len(path)-1):
                    u, v = path[i], path[i+1]
                    if G.has_edge(u, v):
                        bc_topology.append_dst_partition_path(dst, p, [u, v, G[u][v]])

    return bc_topology

import networkx as nx
from typing import List, Dict, Tuple, Set
import heapq
from collections import defaultdict, deque

class BroadCastTopology:
    def __init__(self, src: str, dsts: List[str], num_partitions: int = 4, paths: Dict[str, Dict[str, List[Tuple[str, str, Dict]]]] = None):
        self.src = src
        self.dsts = dsts
        self.num_partitions = num_partitions

        # dict(dst) -> dict(partition_str) -> list of edge tuples (u, v, data)
        if paths is not None:
            self.paths = paths
        else:
            self.paths = {dst: {str(i): [] for i in range(num_partitions)} for dst in dsts}

    def set_num_partitions(self, num_partitions: int):
        self.num_partitions = num_partitions

    def append_dst_partition_path(self, dst: str, partition: int, path_segment: Tuple[str, str, Dict]):
        partition_str = str(partition)
        if dst not in self.paths:
            self.paths[dst] = {str(i): [] for i in range(self.num_partitions)}
        if partition_str not in self.paths[dst]:
            self.paths[dst][partition_str] = []
        self.paths[dst][partition_str].append(path_segment)

def search_algorithm(src: str, dsts: List[str], G: nx.DiGraph, num_partitions: int) -> BroadCastTopology:
    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    # Precompute edge details for easy access
    edge_details = {}
    for u, v, data in G.edges(data=True):
        edge_details[(u, v)] = data

    # Step 1: Find k-shortest paths by cost for each destination
    # The number of paths to consider can be a tuning parameter.
    # A common heuristic is a small multiple of num_partitions.
    k_paths_to_consider = min(20, num_partitions * 3)
    all_candidate_paths = {}

    for dst in dsts:
        candidate_paths_for_dst = []
        try:
            # Use Yen's algorithm for k-shortest simple paths
            gen = nx.shortest_simple_paths(G, src, dst, weight='cost')
            for i, path_nodes in enumerate(gen):
                if i >= k_paths_to_consider:
                    break

                path_cost = 0
                path_edges = []
                valid_path = True
                for j in range(len(path_nodes) - 1):
                    u, v = path_nodes[j], path_nodes[j + 1]
                    if G.has_edge(u, v):
                        path_cost += G[u][v]['cost']
                        path_edges.append((u, v, G[u][v]))
                    else:
                        valid_path = False
                        break

                if valid_path:
                    candidate_paths_for_dst.append({'nodes': path_nodes, 'cost': path_cost, 'edges': path_edges})
        except nx.NetworkXNoPath:
            # If no path is found by Yen's, try a single Dijkstra path
            try:
                path_nodes = nx.dijkstra_path(G, src, dst, weight='cost')
                path_cost = 0
                path_edges = []
                valid_path = True
                for j in range(len(path_nodes) - 1):
                    u, v = path_nodes[j], path_nodes[j + 1]
                    if G.has_edge(u, v):
                        path_cost += G[u][v]['cost']
                        path_edges.append((u, v, G[u][v]))
                    else:
                        valid_path = False
                        break
                if valid_path:
                    candidate_paths_for_dst.append({'nodes': path_nodes, 'cost': path_cost, 'edges': path_edges})
            except nx.NetworkXNoPath:
                # If still no path, this destination is unreachable via cost
                pass

        # Sort candidate paths by cost for this destination
        candidate_paths_for_dst.sort(key=lambda x: x['cost'])
        all_candidate_paths[dst] = candidate_paths_for_dst

    # Step 2: Partition assignment strategy - maximize edge reuse and minimize cost
    # We will assign partitions greedily, prioritizing paths that reuse existing edges.

    # Track the number of times each edge has been used across all assignments
    edge_usage_count = defaultdict(int)
    # Store the assigned path for each (destination, partition)
    partition_assignments = {dst: [None] * num_partitions for dst in dsts}

    # Assign partitions one by one
    for p in range(num_partitions):
        # For each destination, find the best path for this partition
        for dst in dsts:
            best_path_for_partition = None
            min_partition_cost = float('inf')
            best_edge_reuse_score = -1

            if not all_candidate_paths[dst]:
                continue # No paths available for this destination

            # Iterate through available candidate paths for this destination
            for candidate_path in all_candidate_paths[dst]:
                current_path_cost = candidate_path['cost']
                current_path_edges = candidate_path['edges']

                # Calculate a score that balances cost and edge reuse
                # Higher reuse score means more shared edges for this partition
                edge_reuse_score = 0
                for u, v, _ in current_path_edges:
                    if edge_usage_count[(u, v)] > 0:
                        # Reward reusing an edge, with a bonus proportional to its cost
                        # This encourages using cheaper, already utilized edges
                        edge_reuse_score += edge_details[(u, v)]['cost'] * 0.5  # Heuristic factor for reuse bonus

                # A simple scoring function: prioritize paths with higher reuse, then lower cost.
                # We can make this more sophisticated. Here, we prioritize reuse, then cost.
                # If a path has better reuse, we consider it. If reuse is similar, we pick the cheaper one.

                # If we haven't found any assignment yet for this partition/destination,
                # or if the current path offers significantly better reuse,
                # or if reuse is similar but cost is lower.

                # Heuristic: consider a path if it offers better reuse OR if reuse is comparable and cost is better.
                # A more robust approach would be to iterate through all edge assignments and find optimal.
                # For speed, a greedy assignment per partition is better.

                is_better = False
                if best_path_for_partition is None:
                    is_better = True
                else:
                    # Prioritize reuse significantly
                    if edge_reuse_score > best_edge_reuse_score * 1.05: # If reuse is 5% better
                        is_better = True
                    elif abs(edge_reuse_score - best_edge_reuse_score) < 1e-6: # If reuse is very similar
                        if current_path_cost < min_partition_cost: # Then pick the cheaper one
                            is_better = True

                if is_better:
                    best_path_for_partition = candidate_path
                    min_partition_cost = current_path_cost
                    best_edge_reuse_score = edge_reuse_score

            # Assign the best found path to this partition for this destination
            if best_path_for_partition:
                partition_assignments[dst][p] = best_path_for_partition
                # Update edge usage counts for the chosen path
                for u, v, _ in best_path_for_partition['edges']:
                    edge_usage_count[(u, v)] += 1

    # Step 3: Populate the BroadCastTopology object
    for dst in dsts:
        for p in range(num_partitions):
            assigned_path = partition_assignments[dst][p]
            if assigned_path:
                for u, v, data in assigned_path['edges']:
                    bc_topology.append_dst_partition_path(dst, p, (u, v, data))

    return bc_topology

import networkx as nx
from typing import List, Dict, Tuple
import heapq
import math

def search_algorithm(src: str, dsts: List[str], G: nx.DiGraph, num_partitions: int) -> BroadCastTopology:
    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    if not dsts:
        return bc_topology

    # Precompute all-pairs shortest paths by cost (only from src)
    cost_dist = {}
    cost_pred = {}
    for dst in dsts:
        try:
            path = nx.dijkstra_path(G, src, dst, weight='cost')
            cost_dist[dst] = sum(G[u][v]['cost'] for u, v in zip(path[:-1], path[1:]))
            cost_pred[dst] = path
        except (nx.NetworkXNoPath, KeyError):
            cost_dist[dst] = float('inf')
            cost_pred[dst] = None

    # Find candidate intermediate hubs (nodes that appear in multiple shortest paths)
    node_counter = {}
    for dst, path in cost_pred.items():
        if path:
            for node in path[1:-1]:  # Exclude src and dst
                node_counter[node] = node_counter.get(node, 0) + 1

    # Select top hubs by appearance count
    candidate_hubs = sorted(node_counter.items(), key=lambda x: x[1], reverse=True)[:15]
    hubs = [node for node, _ in candidate_hubs if node != src]

    # Build path portfolios for each destination
    portfolios = {}
    for dst in dsts:
        portfolios[dst] = []

        # Direct path
        if cost_pred[dst]:
            portfolios[dst].append(('direct', cost_pred[dst], cost_dist[dst]))

        # Via-hub paths
        for hub in hubs:
            try:
                path1 = nx.dijkstra_path(G, src, hub, weight='cost')
                path2 = nx.dijkstra_path(G, hub, dst, weight='cost')
                if path1 and path2:
                    full_path = path1[:-1] + path2
                    cost = sum(G[u][v]['cost'] for u, v in zip(full_path[:-1], full_path[1:]))
                    portfolios[dst].append((f'hub_{hub}', full_path, cost))
            except (nx.NetworkXNoPath, KeyError):
                continue

        # Sort by cost
        portfolios[dst].sort(key=lambda x: x[2])

    # Initial assignment: assign each partition to best path for each destination
    assignment = {}
    for dst in dsts:
        if portfolios[dst]:
            # Distribute partitions across top paths
            for p in range(num_partitions):
                path_idx = min(p, len(portfolios[dst]) - 1)
                assignment[(dst, p)] = portfolios[dst][path_idx]

    # Edge-sharing optimization: count edge usage
    edge_usage = {}
    for (dst, p), (_, path, _) in assignment.items():
        for i in range(len(path) - 1):
            u, v = path[i], path[i + 1]
            edge_usage[(u, v)] = edge_usage.get((u, v), 0) + 1

    # Try to improve by reassigning partitions to increase edge sharing
    for iteration in range(2):  # Limited iterations for speed
        for dst in dsts:
            if not portfolios[dst]:
                continue

            for p in range(num_partitions):
                current = assignment.get((dst, p))
                if not current:
                    continue

                current_path = current[1]
                current_shared = 0
                for i in range(len(current_path) - 1):
                    u, v = current_path[i], current_path[i + 1]
                    current_shared += edge_usage.get((u, v), 0) - 1  # Exclude self

                best_improvement = 0
                best_alternative = None

                for alt_name, alt_path, alt_cost in portfolios[dst]:
                    if alt_path == current_path:
                        continue

                    # Calculate potential shared edges
                    alt_shared = 0
                    for i in range(len(alt_path) - 1):
                        u, v = alt_path[i], alt_path[i + 1]
                        alt_shared += edge_usage.get((u, v), 0)  # Current usage

                    improvement = alt_shared - current_shared
                    if improvement > best_improvement:
                        best_improvement = improvement
                        best_alternative = (alt_name, alt_path, alt_cost)

                # Switch if improvement found
                if best_improvement > 0:
                    # Update edge usage
                    for i in range(len(current_path) - 1):
                        u, v = current_path[i], current_path[i + 1]
                        edge_usage[(u, v)] = edge_usage.get((u, v), 0) - 1

                    alt_name, alt_path, alt_cost = best_alternative
                    assignment[(dst, p)] = (alt_name, alt_path, alt_cost)

                    for i in range(len(alt_path) - 1):
                        u, v = alt_path[i], alt_path[i + 1]
                        edge_usage[(u, v)] = edge_usage.get((u, v), 0) + 1

    # Build final topology
    for (dst, p), (_, path, _) in assignment.items():
        for i in range(len(path) - 1):
            u, v = path[i], path[i + 1]
            try:
                edge_data = G[u][v]
                bc_topology.append_dst_partition_path(dst, p, (u, v, edge_data))
            except KeyError:
                # Fallback: use any available edge data
                bc_topology.append_dst_partition_path(dst, p, (u, v, {'cost': 1.0, 'throughput': 1.0}))

    # Ensure all destinations have at least one path for each partition
    for dst in dsts:
        for p in range(num_partitions):
            if not bc_topology.paths[dst].get(str(p)):
                # Try to find any path from src to dst
                try:
                    path = nx.dijkstra_path(G, src, dst, weight='cost')
                    for i in range(len(path) - 1):
                        u, v = path[i], path[i + 1]
                        edge_data = G[u][v]
                        bc_topology.append_dst_partition_path(dst, p, (u, v, edge_data))
                except (nx.NetworkXNoPath, KeyError):
                    # Last resort: use BFS
                    try:
                        path = nx.shortest_path(G, src, dst)
                        for i in range(len(path) - 1):
                            u, v = path[i], path[i + 1]
                            edge_data = G.get_edge_data(u, v, {'cost': 1.0, 'throughput': 1.0})
                            bc_topology.append_dst_partition_path(dst, p, (u, v, edge_data))
                    except:
                        pass

    return bc_topology

