    # Precompute all shortest paths from source to each destination
    shortest_paths = {}
    for dst in dsts:
        try:
            shortest_paths[dst] = nx.dijkstra_path(G, src, dst, weight='cost')
        except nx.NetworkXNoPath:
            shortest_paths[dst] = None

    # Group destinations by cloud provider for better optimization
    cloud_groups = defaultdict(list)
    for dst in dsts:
        if dst.startswith("aws:"):
            cloud_groups["aws"].append(dst)
        elif dst.startswith("azure:"):
            cloud_groups["azure"].append(dst)
        elif dst.startswith("gcp:"):
            cloud_groups["gcp"].append(dst)
        else:
            cloud_groups["other"].append(dst)

    # For each cloud group, find optimal hub node
    cloud_hubs = {}
    for cloud, group_dsts in cloud_groups.items():
        if not group_dsts or cloud == "other":
            continue

        # Find best hub based on average cost to all destinations in group
        best_hub = None
        min_avg_cost = float('inf')

        # Consider all nodes from the same cloud as potential hubs
        candidate_hubs = [node for node in G.nodes() if node.startswith(cloud + ":")]
        if not candidate_hubs:
            continue

        for hub in candidate_hubs:
            total_cost = 0
            valid = True

            # Calculate cost from source to hub and then to each destination
            for dst in group_dsts:
                if shortest_paths[dst] is None:
                    continue
                try:
                    # Cost from src to hub
                    src_to_hub_cost = nx.dijkstra_path_length(G, src, hub, weight='cost')
                    # Cost from hub to dst
                    hub_to_dst_cost = nx.dijkstra_path_length(G, hub, dst, weight='cost')
                    total_cost += src_to_hub_cost + hub_to_dst_cost
                except:
                    valid = False
                    break

            if valid and total_cost < min_avg_cost:
                min_avg_cost = total_cost
                best_hub = hub

        if best_hub:
            cloud_hubs[cloud] = best_hub

    # Build broadcast tree with optimized routing
    used_edges = defaultdict(list)  # edge -> list of (dst, partition)

    # Process cloud groups with hubs
    for cloud, hub in cloud_hubs.items():
        group_dsts = cloud_groups[cloud]

        # Build paths from source to hub
        try:
            src_to_hub_path = nx.dijkstra_path(G, src, hub, weight='cost')
            src_to_hub_cost = nx.dijkstra_path_length(G, src, hub, weight='cost')
        except:
            continue

        # For each destination in this cloud group
        for dst in group_dsts:
            if shortest_paths[dst] is None:
                continue

            # Get path from hub to destination
            try:
                hub_to_dst_path = nx.dijkstra_path(G, hub, dst, weight='cost')
                hub_to_dst_cost = nx.dijkstra_path_length(G, hub, dst, weight='cost')
            except:
                continue

            # Combine paths (avoid duplicate hub)
            full_path = src_to_hub_path[:-1] + hub_to_dst_path

            # Add edges for each partition
            for partition in range(num_partitions):
                # Distribute partitions across different routes for better throughput
                path_to_use = full_path

                # Add each edge to the topology
                for i in range(len(path_to_use) - 1):
                    u, v = path_to_use[i], path_to_use[i+1]
                    edge_key = (u, v)
                    used_edges[edge_key].append((dst, partition))
                    bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])

    # Process other destinations that weren't assigned to a cloud group
    all_processed = set()
    for edges in used_edges.values():
        for dst, _ in edges:
            all_processed.add(dst)

    # Handle remaining destinations with direct paths
    for dst in dsts:
        if dst in all_processed:
            continue

        if shortest_paths[dst] is None:
            continue

        # Use direct shortest path for remaining destinations
        path = shortest_paths[dst]
        for partition in range(num_partitions):
            for i in range(len(path) - 1):
                u, v = path[i], path[i+1]
                bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])

    # Ensure all destinations have paths for all partitions
    for dst in dsts:
        for partition in range(num_partitions):
            # Check if path exists
            if not bc_topology.paths[dst][str(partition)]:
                # Try to find an alternative path if original fails
                try:
                    path = nx.shortest_path(G, src, dst)
                    for i in range(len(path) - 1):
                        u, v = path[i], path[i+1]
                        bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])
