                        break

    return bc_topology

import networkx as nx
from typing import List, Dict, Tuple
import heapq
from collections import defaultdict

class BroadCastTopology:
    """Stores broadcast topology with paths for each (destination, partition) pair."""

    def __init__(self, src: str, dsts: List[str], num_partitions: int = 4, paths: Dict[str, Dict[str, List[Tuple[str, str, Dict]]]] = None):
        self.src = src
        self.dsts = dsts
        self.num_partitions = num_partitions

        # dict(dst) -> dict(partition_str) -> list of edge tuples (u, v, data)
        if paths is not None:
            self.paths = paths
        else:
            self.paths = {dst: {str(i): [] for i in range(num_partitions)} for dst in dsts}

    def set_num_partitions(self, num_partitions: int):
        self.num_partitions = num_partitions

    def append_dst_partition_path(self, dst: str, partition: int, path_segment: Tuple[str, str, Dict]):
        partition_str = str(partition)
        if dst not in self.paths:
            self.paths[dst] = {str(i): [] for i in range(self.num_partitions)}
        if partition_str not in self.paths[dst]:
            self.paths[dst][partition_str] = []
        self.paths[dst][partition_str].append(path_segment)


def search_algorithm(src: str, dsts: List[str], G: nx.DiGraph, num_partitions: int) -> BroadCastTopology:
    """
    Find optimal broadcast topology minimizing transfer cost.
    This version uses Yen's k-shortest path algorithm to find multiple path options
    and then greedily assigns partitions to paths that maximize edge reuse and minimize cost.
    """

    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    # Step 1: Find k-shortest paths by cost for each destination
    # We look for a reasonable number of shortest paths to allow for optimization.
    # The number of paths to consider can be a tuning parameter.
    k_paths_to_consider = min(3 * num_partitions + 5, len(G.edges)) # Heuristic for k

    all_candidate_paths_for_dsts = {}
    for dst in dsts:
        candidate_paths = []
        try:
            # Use Yen's algorithm for k-shortest simple paths
            gen = nx.shortest_simple_paths(G, src, dst, weight='cost')
            for i, path_nodes in enumerate(gen):
                if i >= k_paths_to_consider:
                    break

                path_cost = 0
                path_edges_data = []
                valid_path = True
                for j in range(len(path_nodes) - 1):
                    u, v = path_nodes[j], path_nodes[j + 1]
                    if G.has_edge(u, v):
                        edge_data = G[u][v]
                        path_cost += edge_data['cost']
                        path_edges_data.append((u, v, edge_data))
                    else:
                        valid_path = False
                        break

                if valid_path:
                    candidate_paths.append({'nodes': path_nodes, 'cost': path_cost, 'edges': path_edges_data})
        except nx.NetworkXNoPath:
            # If Yen's algorithm fails, try Dijkstra as a fallback (should cover most cases if a path exists)
            try:
                path_nodes = nx.dijkstra_path(G, src, dst, weight='cost')
                path_cost = 0
                path_edges_data = []
                for j in range(len(path_nodes) - 1):
                    u, v = path_nodes[j], path_nodes[j + 1]
                    edge_data = G[u][v]
                    path_cost += edge_data['cost']
                    path_edges_data.append((u, v, edge_data))
                candidate_paths.append({'nodes': path_nodes, 'cost': path_cost, 'edges': path_edges_data})
            except nx.NetworkXNoPath:
                # If still no path, this destination is unreachable.
                print(f"Warning: No path found from {src} to {dst}")

        # Sort candidate paths by cost for this destination
        candidate_paths.sort(key=lambda x: x['cost'])
        all_candidate_paths_for_dsts[dst] = candidate_paths

    # Step 2: Assign partitions to paths greedily.
    # Prioritize paths that maximize edge reuse and minimize overall cost.

    # Track the number of times each edge has been used across all assignments.
    edge_usage_count = defaultdict(int)

    # Store the assignment of a path to each (destination, partition) pair.
    # This will be a list of paths, one for each partition for each destination.
    partition_assignments_per_dst = {dst: [None] * num_partitions for dst in dsts}

    # Iterate through each partition and assign the best path for it.
    for p in range(num_partitions):
        # For the current partition 'p', find the best assignment across all destinations.
        for dst in dsts:
            best_path_for_this_partition = None
            min_path_cost = float('inf')
            max_reuse_score = -1.0 # Score based on how many times edges are reused

            if not all_candidate_paths_for_dsts[dst]:
                continue # No paths available for this destination.

            # Evaluate each candidate path for this destination and partition.
            for candidate_path in all_candidate_paths_for_dsts[dst]:
                current_path_cost = candidate_path['cost']
                current_path_edges = candidate_path['edges']

                # Calculate a reuse score. Higher means more shared edges.
                # We can weight reuse based on the cost of the edge to encourage reuse of cheaper edges.
                current_reuse_score = 0
                for u, v, data in current_path_edges:
                    if edge_usage_count[(u, v)] > 0:
                        # Reward reusing an edge. The reward can be proportional to the edge's cost.
                        current_reuse_score += data.get('cost', 1.0) * 0.5 # Heuristic factor for reuse bonus

                # Decision criteria:
                # 1. If no path has been assigned yet for this (dst, partition), take the first one.
                # 2. If the current path offers significantly better reuse, take it.
                # 3. If reuse is very similar, take the path with lower cost.

                is_better = False
                if best_path_for_this_partition is None:
                    is_better = True
                else:
                    # Heuristic: Prioritize reuse. If reuse is substantially better, choose it.
                    # If reuse is comparable, then pick the one with lower cost.
                    reuse_difference_threshold = 0.05 # 5% difference in reuse score as threshold

                    if current_reuse_score > max_reuse_score * (1 + reuse_difference_threshold):
                        is_better = True
                    elif abs(current_reuse_score - max_reuse_score) < 1e-6: # If reuse scores are essentially equal
                        if current_path_cost < min_path_cost:
                            is_better = True

                if is_better:
                    best_path_for_this_partition = candidate_path
                    min_path_cost = current_path_cost
                    max_reuse_score = current_reuse_score

            # Assign the best found path for this partition and destination.
            if best_path_for_this_partition:
                partition_assignments_per_dst[dst][p] = best_path_for_this_partition
                # Update the usage count for the edges in the assigned path.
                for u, v, data in best_path_for_this_partition['edges']:
                    edge_usage_count[(u, v)] += 1

    # Step 3: Populate the BroadCastTopology object with the selected paths.
    for dst in dsts:
        for p in range(num_partitions):
            assigned_path = partition_assignments_per_dst[dst][p]
            if assigned_path:
                # Add each segment of the assigned path to the topology.
                for u, v, data in assigned_path['edges']:
                    bc_topology.append_dst_partition_path(dst, p, (u, v, data))

    return bc_topology

import networkx as nx
from typing import List, Dict, Tuple
import heapq
from collections import defaultdict

def search_algorithm(src: str, dsts: List[str], G: nx.DiGraph, num_partitions: int) -> BroadCastTopology:
    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    # Remove source from destinations if present
    destinations = [d for d in dsts if d != src]
    if not destinations:
        return bc_topology

    # Create an undirected version for connectivity checks
    G_undirected = G.to_undirected()

    # Precompute all-pairs shortest paths for cost and hop distance
    # Use Dijkstra for cost-optimal paths to each destination
    cost_paths = {}
    cost_distances = {}

    # Dijkstra from source to all nodes with cost as weight
    pq = [(0, src, [])]  # (cost, node, path)
    visited = set()

    while pq and len(visited) < len(G.nodes()):
        cost, node, path = heapq.heappop(pq)
        if node in visited:
            continue
        visited.add(node)

        current_path = path + [node]
        if node in destinations:
            cost_paths[node] = current_path.copy()
            cost_distances[node] = cost

        for neighbor in G.successors(node):
            if neighbor not in visited:
                edge_cost = G[node][neighbor]['cost']
                heapq.heappush(pq, (cost + edge_cost, neighbor, current_path))

    # Find alternative paths using edge-disjoint approach
    edge_usage = defaultdict(int)
    partition_assignments = {dst: [None] * num_partitions for dst in destinations}

    # Phase 1: Assign each partition to a different path for each destination
    # Use BFS to find alternative paths that minimize new edge usage
    for dst in destinations:
        if dst not in cost_paths:
            continue

        # Get the primary cost-optimal path
        primary_path = cost_paths[dst]

        # Assign partitions to paths, trying to reuse edges
        for partition in range(num_partitions):
            if partition == 0:
                # First partition uses the primary path
                best_path = primary_path
            else:
                # Try to find alternative paths that reuse existing edges
                best_path = None
                best_score = float('inf')

                # Try k-shortest paths with modified weights to encourage edge reuse
                try:
                    # Create a copy of the graph with modified weights
                    H = G.copy()

                    # Increase weight for heavily used edges to encourage diversity
                    for u, v in H.edges():
                        if edge_usage[(u, v)] > 0:
                            # Reduce cost for shared edges to encourage reuse
                            H[u][v]['modified_cost'] = H[u][v]['cost'] * max(0.1, 1.0 / (edge_usage[(u, v)] + 1))
                        else:
                            H[u][v]['modified_cost'] = H[u][v]['cost']

                    # Find k alternative paths
                    k = min(5, partition + 2)
                    path_gen = nx.shortest_simple_paths(H, src, dst, weight='modified_cost')

                    for i, alt_path in enumerate(path_gen):
                        if i >= k:
                            break

                        # Calculate score: cost + penalty for new edges
                        score = 0
                        new_edges = 0
                        for j in range(len(alt_path) - 1):
                            u, v = alt_path[j], alt_path[j + 1]
                            score += H[u][v]['cost']
                            if edge_usage[(u, v)] == 0:
                                new_edges += 1

                        # Add penalty for new edges to encourage reuse
                        score += new_edges * 0.1

                        if score < best_score:
                            best_score = score
                            best_path = alt_path

                except:
                    # Fall back to primary path
                    best_path = primary_path

            # Record the path for this partition
            if best_path:
                partition_assignments[dst][partition] = best_path

                # Update edge usage
                for j in range(len(best_path) - 1):
                    u, v = best_path[j], best_path[j + 1]
                    edge_usage[(u, v)] += 1

    # Phase 2: Fill in any missing assignments with primary paths
    for dst in destinations:
        primary_path = cost_paths.get(dst)
        if not primary_path:
            # Try to find any path to destination
            try:
                primary_path = nx.shortest_path(G, src, dst)
            except:
                continue

        for partition in range(num_partitions):
            if not partition_assignments[dst][partition]:
                partition_assignments[dst][partition] = primary_path

    # Phase 3: Build the topology with the assigned paths
    for dst in destinations:
        for partition in range(num_partitions):
            path = partition_assignments[dst][partition]
            if path:
                for i in range(len(path) - 1):
                    u, v = path[i], path[i + 1]
                    bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])

    return bc_topology

