def search_algorithm(src: str, dsts: List[str], G: nx.DiGraph, num_partitions: int) -> BroadCastTopology:
    bc_topology = BroadCastTopology(src, dsts, num_partitions)
    if src in dsts:
        dsts = [d for d in dsts if d != src]

    if not dsts:
        return bc_topology

    edge_throughput = {}
    for u, v, data in G.edges(data=True):
        edge_throughput[(u, v)] = data.get('throughput', 1.0)

    candidate_paths = {}
    for dst in dsts:
        try:
            base_path = nx.dijkstra_path(G, src, dst, weight='cost')
            candidates = [base_path]
            try:
                for path in nx.shortest_simple_paths(G, src, dst, weight='cost'):
                    if path not in candidates:
                        candidates.append(path)
                    if len(candidates) >= min(5, num_partitions):
                        break
            except:
                pass
            candidate_paths[dst] = candidates
        except nx.NetworkXNoPath:
            candidate_paths[dst] = []

    path_edge_sets = {}
    path_costs = {}
    for dst in dsts:
        path_edge_sets[dst] = []
        path_costs[dst] = []
        for path in candidate_paths[dst]:
            edges = []
            cost = 0.0
            for i in range(len(path)-1):
                u, v = path[i], path[i+1]
                edges.append((u, v))
                cost += G[u][v]['cost']
            path_edge_sets[dst].append(set(edges))
            path_costs[dst].append(cost)

    partitions_per_dst = {dst: [None]*num_partitions for dst in dsts}
    edge_usage = defaultdict(int)

    for p in range(num_partitions):
        for dst in dsts:
            if not candidate_paths[dst]:
                continue
            best_idx = 0
            best_score = -float('inf')
            for idx, edge_set in enumerate(path_edge_sets[dst]):
                reuse = sum(edge_usage[e] for e in edge_set)
                cost_penalty = path_costs[dst][idx] * 0.02
                score = reuse - cost_penalty
                if score > best_score:
                    best_score = score
                    best_idx = idx
            partitions_per_dst[dst][p] = best_idx
            for e in path_edge_sets[dst][best_idx]:
                edge_usage[e] += 1

    for dst in dsts:
        for p in range(num_partitions):
            idx = partitions_per_dst[dst][p]
            if idx is None:
                continue
            path = candidate_paths[dst][idx]
            for i in range(len(path)-1):
                u, v = path[i], path[i+1]
                bc_topology.append_dst_partition_path(dst, p, (u, v, G[u][v]))

    return bc_topology

