def search_algorithm(src: str, dsts: List[str], G: nx.DiGraph, num_partitions: int) -> BroadCastTopology:
    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    # Clean graph: remove incoming edges to source and self-loops
    H = G.copy()
    H.remove_edges_from(list(H.in_edges(src)) + list(nx.selfloop_edges(H)))

    # Precompute shortest paths from source to all nodes by cost
    all_dists = {}
    all_paths = {}
    for node in H.nodes():
        try:
            dist, path = nx.single_source_dijkstra(H, src, node, weight='cost')
            all_dists[node] = dist
            all_paths[node] = path
        except:
            all_dists[node] = float('inf')
            all_paths[node] = []

    # Generate multiple diverse paths for each destination
    dst_paths = defaultdict(list)
    for dst in dsts:
        if dst not in H.nodes():
            continue

        # Direct shortest path
        if dst in all_paths and all_paths[dst]:
            dst_paths[dst].append(all_paths[dst])

        # Paths through major cloud hubs
        cloud_prefixes = ['aws:', 'azure:', 'gcp:']
        for prefix in cloud_prefixes:
            best_hub = None
            best_cost = float('inf')

            for node in H.nodes():
                if node.startswith(prefix) and node != dst:
                    if node in all_dists:
                        try:
                            hub_to_dst = nx.dijkstra_path_length(H, node, dst, weight='cost')
                            total_cost = all_dists[node] + hub_to_dst
                            if total_cost < best_cost:
                                best_cost = total_cost
                                best_hub = node
                        except:
                            continue

            if best_hub:
                try:
                    path1 = all_paths[best_hub]
                    path2 = nx.dijkstra_path(H, best_hub, dst, weight='cost')
                    if path1 and path2:
                        combined = path1[:-1] + path2 if path1[-1] == path2[0] else path1 + path2
                        if len(combined) >= 2:
                            dst_paths[dst].append(combined)
                except:
                    pass

        # Ensure at least one path exists
        if not dst_paths[dst]:
            # Try BFS as last resort
            try:
                path = nx.shortest_path(H, src, dst)
                if path:
                    dst_paths[dst].append(path)
            except:
                continue

    # Group destinations by cloud for better sharing opportunities
    cloud_groups = defaultdict(list)
    for dst in dsts:
        if dst.startswith('aws:'):
            cloud_groups['aws'].append(dst)
        elif dst.startswith('azure:'):
            cloud_groups['azure'].append(dst)
        elif dst.startswith('gcp:'):
            cloud_groups['gcp'].append(dst)
        else:
            cloud_groups['other'].append(dst)

    # Find optimal hub for each cloud group
    cloud_hubs = {}
    for cloud, group_dsts in cloud_groups.items():
        if not group_dsts:
            continue

        best_hub = None
        best_avg_cost = float('inf')

        # Consider source and cloud-specific nodes as potential hubs
        candidates = [src]
        for node in H.nodes():
            if cloud == 'other' or node.startswith(cloud + ':'):
                candidates.append(node)

        for hub in candidates:
            total_cost = 0
            reachable = 0

            for dst in group_dsts:
                try:
                    if hub == src:
                        cost = all_dists.get(dst, float('inf'))
                    else:
                        if hub not in all_dists:
                            continue
                        cost1 = all_dists[hub]
                        cost2 = nx.dijkstra_path_length(H, hub, dst, weight='cost')
                        cost = cost1 + cost2

                    if cost < float('inf'):
                        total_cost += cost
                        reachable += 1
                except:
                    continue

            if reachable == len(group_dsts) and reachable > 0:
                avg_cost = total_cost / reachable
                if avg_cost < best_avg_cost:
                    best_avg_cost = avg_cost
                    best_hub = hub

        cloud_hubs[cloud] = best_hub if best_hub else src

    # Add cloud-hub paths to destination portfolios
    for cloud, hub in cloud_hubs.items():
        if hub == src:
            continue

        for dst in cloud_groups[cloud]:
            try:
                if hub == src:
                    path = all_paths[dst]
                else:
                    if hub not in all_paths:
                        continue
                    path1 = all_paths[hub]
                    path2 = nx.dijkstra_path(H, hub, dst, weight='cost')
                    path = path1[:-1] + path2 if path1[-1] == path2[0] else path1 + path2

                if path and path not in dst_paths[dst]:
                    dst_paths[dst].append(path)
            except:
                continue

    # Edge costs for quick lookup
    edge_cost = {}
    for u, v, data in H.edges(data=True):
        edge_cost[(u, v)] = data['cost']

    # Initialize partition assignments with cheapest paths
    assignments = {}
    edge_usage = defaultdict(int)

    for dst in dsts:
        if not dst_paths[dst]:
            continue

        # Sort paths by total cost
        sorted_paths = sorted(dst_paths[dst],
                            key=lambda p: sum(edge_cost.get((p[i], p[i+1]), float('inf'))
                                            for i in range(len(p)-1)))

        # Assign partitions round-robin across cheapest paths
        for p in range(num_partitions):
            path_idx = p % min(len(sorted_paths), max(1, num_partitions // 2))
            path = sorted_paths[path_idx]
            assignments[(dst, p)] = path

            # Update edge usage
            for i in range(len(path)-1):
                edge_usage[(path[i], path[i+1])] += 1

    # Local optimization: reassign partitions to increase edge sharing
    for iteration in range(10):
        improved = False

        for dst in dsts:
            if not dst_paths[dst]:
                continue

            for p in range(num_partitions):
                current_path = assignments.get((dst, p))
                if not current_path:
                    continue

                # Calculate current cost and sharing benefit
                current_cost = sum(edge_cost.get((current_path[i], current_path[i+1]), float('inf'))
                                 for i in range(len(current_path)-1))
                current_shared = sum(max(0, edge_usage[(current_path[i], current_path[i+1])] - 1)
                                   for i in range(len(current_path)-1))

                best_score = current_cost - current_shared * 0.3  # Weight sharing vs cost
                best_path = current_path

                # Try alternative paths
                for alt_path in dst_paths[dst]:
                    if alt_path == current_path:
                        continue

                    alt_cost = sum(edge_cost.get((alt_path[i], alt_path[i+1]), float('inf'))
                                 for i in range(len(alt_path)-1))
                    alt_shared = sum(edge_usage[(alt_path[i], alt_path[i+1])]
                                   for i in range(len(alt_path)-1))

                    alt_score = alt_cost - alt_shared * 0.3

                    if alt_score < best_score:
                        best_score = alt_score
                        best_path = alt_path

                if best_path != current_path:
                    improved = True

                    # Update edge usage
                    for i in range(len(current_path)-1):
                        edge = (current_path[i], current_path[i+1])
                        edge_usage[edge] -= 1

                    for i in range(len(best_path)-1):
                        edge = (best_path[i], best_path[i+1])
                        edge_usage[edge] += 1

                    assignments[(dst, p)] = best_path

        if not improved:
            break

    # Build final topology
    for (dst, p), path in assignments.items():
        for i in range(len(path)-1):
            u, v = path[i], path[i+1]
            if G.has_edge(u, v):
                bc_topology.append_dst_partition_path(dst, p, [u, v, G[u][v]])

    # Ensure all destinations have paths for all partitions
    for dst in dsts:
        for p in range(num_partitions):
            if not bc_topology.paths.get(dst, {}).get(str(p), []):
                # Fallback to cheapest path
                if dst_paths[dst]:
                    cheapest_path = min(dst_paths[dst],
                                      key=lambda pth: sum(edge_cost.get((pth[i], pth[i+1]), float('inf'))
                                                        for i in range(len(pth)-1)))
                    for i in range(len(cheapest_path)-1):
                        u, v = cheapest_path[i], cheapest_path[i+1]
                        if G.has_edge(u, v):
                            bc_topology.append_dst_partition_path(dst, p, [u, v, G[u][v]])

    return bc_topology

import networkx as nx
from typing import List, Dict, Tuple
