from collections import defaultdict

def search_algorithm(src: str, dsts: List[str], G: nx.DiGraph, num_partitions: int) -> BroadCastTopology:
    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    # Step 1: Group destinations by cloud provider
    cloud_groups = defaultdict(list)
    for dst in dsts:
        # Extract cloud provider from node name (format: "provider:region-zone")
        if dst.startswith("aws:"):
            cloud_groups["aws"].append(dst)
        elif dst.startswith("azure:"):
            cloud_groups["azure"].append(dst)
        elif dst.startswith("gcp:"):
            cloud_groups["gcp"].append(dst)
        else:
            cloud_groups["other"].append(dst)

    # Step 2: Find strategic root nodes for each cloud
    # Choose a central node within each cloud that's well-connected
    cloud_roots = {}

    # Helper function to find central node within a set of nodes
    def find_central_node(nodes):
        if not nodes:
            return src
        # Find node with maximum intra-cloud connectivity
        best_node = nodes[0]
        best_score = 0
        for node in nodes:
            # Count intra-cloud edges
            score = 0
            for neighbor in G.successors(node):
                if any(neighbor.startswith(cloud + ":") for cloud in ["aws", "azure", "gcp"]):
                    # Check if same cloud
                    node_cloud = node.split(":")[0]
                    neighbor_cloud = neighbor.split(":")[0]
                    if node_cloud == neighbor_cloud:
                        score += 1
            if score > best_score:
                best_score = score
                best_node = node
        return best_node

    for cloud, nodes in cloud_groups.items():
        if nodes:
            cloud_roots[cloud] = find_central_node(nodes)

    # Step 3: Build intra-cloud trees for each cloud group
    cloud_trees = {}

    for cloud, root in cloud_roots.items():
        if cloud not in cloud_groups or not cloud_groups[cloud]:
            continue

        # Create a subgraph with only intra-cloud edges for this cloud
        subgraph_nodes = [n for n in G.nodes() if n.startswith(cloud + ":")]
        if src not in subgraph_nodes:
            subgraph_nodes.append(src)

        # Build minimum spanning tree/Steiner tree approximation
        # Use Dijkstra from root to all nodes in this cloud
        try:
            pred, _ = nx.dijkstra_predecessor_and_distance(G, root, weight='cost')

            # Build tree edges
            tree_edges = set()
            for node in cloud_groups[cloud]:
                if node in pred and pred[node]:
                    # Reconstruct path from root to node
                    current = node
                    while current != root and current in pred and pred[current]:
                        parent = pred[current][0]  # Take first predecessor
                        if (parent, current) in G.edges():
                            tree_edges.add((parent, current))
                        current = parent

            cloud_trees[cloud] = tree_edges
        except:
            cloud_trees[cloud] = set()

    # Step 4: Connect cloud trees to source using minimal inter-cloud edges
    connected_trees = {}

    for cloud, tree_edges in cloud_trees.items():
        if cloud_roots[cloud] == src:
            connected_trees[cloud] = tree_edges
            continue

        # Find cheapest path from src to cloud root
        try:
            path = nx.dijkstra_path(G, src, cloud_roots[cloud], weight='cost')
            connecting_edges = set()
            for i in range(len(path) - 1):
                connecting_edges.add((path[i], path[i+1]))

            # Combine connecting edges with tree edges
            connected_trees[cloud] = tree_edges.union(connecting_edges)
        except:
            connected_trees[cloud] = tree_edges

    # Step 5: For destinations not in major clouds, use direct paths
    other_dsts = cloud_groups.get("other", [])
    for dst in other_dsts:
        try:
            path = nx.dijkstra_path(G, src, dst, weight='cost')
            for i in range(len(path) - 1):
                connected_trees[dst] = connected_trees.get(dst, set())
                connected_trees[dst].add((path[i], path[i+1]))
        except:
            pass

    # Step 6: Assign partitions to optimize edge sharing
    # Create a mapping from edge to list of (dst, partition) pairs
    edge_usage = defaultdict(list)

    # First pass: assign all partitions using cloud-specific trees
    for cloud, tree_edges in connected_trees.items():
        dst_list = cloud_groups.get(cloud, [])
        if not dst_list:
            # Handle individual destination case
            if cloud in other_dsts:
                dst_list = [cloud]

        for dst in dst_list:
            # Find path from src to dst using tree edges
            # Perform BFS on tree edges
            visited = set()
            queue = [(src, [])]
            found_path = None

            while queue and not found_path:
                node, path = queue.pop(0)
                if node == dst:
                    found_path = path + [dst]
                    break

                visited.add(node)
                # Follow tree edges
                for (u, v) in tree_edges:
                    if u == node and v not in visited:
                        queue.append((v, path + [u]))

            if found_path:
                # Assign all partitions to this path
                for partition in range(num_partitions):
                    for i in range(len(found_path) - 1):
                        u, v = found_path[i], found_path[i+1]
                        if G.has_edge(u, v):
                            edge_usage[(u, v)].append((dst, partition))
                            bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])

    # Step 7: For any unassigned (dst, partition) pairs, use direct shortest path
    for dst in dsts:
        for partition in range(num_partitions):
            # Check if this pair was assigned
            assigned = False
            for edges in edge_usage.values():
                if (dst, partition) in edges:
                    assigned = True
                    break

            if not assigned:
                try:
                    path = nx.dijkstra_path(G, src, dst, weight='cost')
                    for i in range(len(path) - 1):
                        u, v = path[i], path[i+1]
                        bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])
                except:
                    # Last resort: use any available path
                    try:
                        for neighbor in G.successors(src):
                            if G.has_edge(src, neighbor) and G.has_edge(neighbor, dst):
                                bc_topology.append_dst_partition_path(dst, partition, [src, neighbor, G[src][neighbor]])
                                bc_topology.append_dst_partition_path(dst, partition, [neighbor, dst, G[neighbor][dst]])
                                break
                    except:
                        pass

    return bc_topology

