from collections import defaultdict

def search_algorithm(src: str, dsts: List[str], G: nx.DiGraph, num_partitions: int) -> BroadCastTopology:
    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    # Precompute all shortest paths from source to destinations
    shortest_paths = {}
    for dst in dsts:
        try:
            path = nx.dijkstra_path(G, src, dst, weight='cost')
            shortest_paths[dst] = path
        except nx.NetworkXNoPath:
            shortest_paths[dst] = None

    # Group destinations by cloud provider for optimization
    provider_groups = defaultdict(list)
    for dst in dsts:
        if dst.startswith("aws:"):
            provider_groups["aws"].append(dst)
        elif dst.startswith("azure:"):
            provider_groups["azure"].append(dst)
        elif dst.startswith("gcp:"):
            provider_groups["gcp"].append(dst)
        else:
            provider_groups["other"].append(dst)

    # For cross-cloud scenarios, find optimal hub points
    provider_hubs = {}
    for provider, group_dsts in provider_groups.items():
        if not group_dsts or provider == "other":
            continue

        # Find best internal hub for this provider group
        best_hub = None
        min_total_cost = float('inf')

        # Consider all nodes from same provider
        candidate_hubs = [node for node in G.nodes() if node.startswith(provider + ":")]
        for hub in candidate_hubs:
            total_cost = 0
            valid = True

            try:
                # Cost from source to hub
                src_to_hub_cost = nx.dijkstra_path_length(G, src, hub, weight='cost')
                for dst in group_dsts:
                    try:
                        hub_to_dst_cost = nx.dijkstra_path_length(G, hub, dst, weight='cost')
                        total_cost += src_to_hub_cost + hub_to_dst_cost
                    except nx.NetworkXNoPath:
                        valid = False
                        break
            except nx.NetworkXNoPath:
                continue

            if valid and total_cost < min_total_cost:
                min_total_cost = total_cost
                best_hub = hub

        if best_hub:
            provider_hubs[provider] = best_hub

    # Build paths for all destinations
    for dst in dsts:
        # Direct path as fallback
        current_path = []
        if dst in shortest_paths and shortest_paths[dst]:
            current_path = shortest_paths[dst]
        else:
            # Try direct edge if exists, otherwise source only
            if G.has_edge(src, dst):
                current_path = [src, dst]
            else:
                current_path = [src]

        # Try to use hub if available for this provider
        provider = None
        if dst.startswith("aws:"):
            provider = "aws"
        elif dst.startswith("azure:"):
            provider = "azure"
        elif dst.startswith("gcp:"):
            provider = "gcp"

        if provider and provider in provider_hubs:
            hub = provider_hubs[provider]
            try:
                path_to_hub = nx.dijkstra_path(G, src, hub, weight='cost')
                path_from_hub = nx.dijkstra_path(G, hub, dst, weight='cost')
                # Combine paths (avoiding duplicate hub node)
                current_path = path_to_hub[:-1] + path_from_hub
            except nx.NetworkXNoPath:
                pass  # Use existing direct path

        # Get diverse paths by avoiding used edges
        paths = [current_path]
        temp_G = G.copy()

        # Try to find diverse paths avoiding previously used edges
        for _ in range(3):
            if len(paths) >= num_partitions:
                break

            try:
                # Temporarily increase cost of edges already used
                for existing_path in paths:
                    for i in range(len(existing_path) - 1):
                        u, v = existing_path[i], existing_path[i+1]
                        if temp_G.has_edge(u, v):
                            temp_G[u][v]['cost'] *= 1.5  # Penalize more heavily

                alt_path = nx.dijkstra_path(temp_G, src, dst, weight='cost')
                if alt_path not in paths:
                    paths.append(alt_path)
            except nx.NetworkXNoPath:
                break

        # Assign partitions to paths using round-robin
        for partition in range(num_partitions):
            path_idx = partition % len(paths)
            path = paths[path_idx]

            # Add each edge to topology
            for i in range(len(path) - 1):
                u, v = path[i], path[i+1]
                if G.has_edge(u, v):
                    bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])

    return bc_topology

