def search_algorithm(src: str, dsts: List[str], G: nx.DiGraph, num_partitions: int) -> BroadCastTopology:
    # Create a working graph without incoming edges to source or self-loops
    H = G.copy()
    if src in H:
        for pred in list(H.predecessors(src)):
            H.remove_edge(pred, src)
    H.remove_edges_from(list(nx.selfloop_edges(H)))

    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    # Precompute shortest paths by cost for all destinations
    cost_paths = {}
    for dst in dsts:
        try:
            cost_paths[dst] = nx.dijkstra_path(H, src, dst, weight='cost')
        except nx.NetworkXNoPath:
            cost_paths[dst] = None

    # For each destination, assign partitions to paths with diversity
    for dst in dsts:
        path = cost_paths[dst]
        if not path:
            continue

        # Create multiple diverse paths by temporarily modifying edge weights
        # Use a greedy approach to find different paths
        all_paths = [path]

        # Try to find alternative paths by modifying edge weights
        temp_G = H.copy()

        # Temporarily increase cost of edges in the first path to encourage different routes
        edges_in_first_path = list(zip(path[:-1], path[1:]))
        for u, v in edges_in_first_path:
            if u in temp_G and v in temp_G[u]:
                temp_G[u][v]['cost'] *= 2

        # Try to find one more distinct path
        try:
            alt_path = nx.dijkstra_path(temp_G, src, dst, weight='cost')
            if alt_path != path:
                all_paths.append(alt_path)
        except nx.NetworkXNoPath:
            pass

        # If we have less than num_partitions paths, duplicate existing ones
        while len(all_paths) < num_partitions:
            all_paths.extend(all_paths[:num_partitions - len(all_paths)])

        # Assign paths to partitions with round-robin
        for partition in range(num_partitions):
            path_idx = partition % len(all_paths)
            selected_path = all_paths[path_idx]

            # Add each edge in the path to topology
            for i in range(len(selected_path) - 1):
                s, t = selected_path[i], selected_path[i + 1]
                bc_topology.append_dst_partition_path(dst, partition, [s, t, G[s][t]])

    return bc_topology

import networkx as nx
from typing import List, Dict, Tuple
import heapq

def search_algorithm(src: str, dsts: List[str], G: nx.DiGraph, num_partitions: int) -> BroadCastTopology:
    # Clean graph
    G_clean = G.copy()
    G_clean.remove_edges_from(list(G_clean.in_edges(src)) + list(nx.selfloop_edges(G_clean)))

    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    # First, compute cheapest single path for each destination as fallback
    fallback_paths = {}
    for dst in dsts:
        try:
            path = nx.dijkstra_path(G_clean, src, dst, weight='cost')
            fallback_paths[dst] = path
        except:
            fallback_paths[dst] = []

    # For each partition, compute Steiner-tree-like broadcast using cost as weight
    # We'll use a greedy approach: for each partition, build a tree that minimizes
    # incremental cost to reach all destinations
    for partition in range(num_partitions):
        # Start with source
        reached = {src}
        paths_to_dest = {src: []}

        # Priority queue: (cost_to_add, node, parent)
        pq = []
        for v in G_clean.neighbors(src):
            if v != src:
                cost = G_clean[src][v]['cost']
                heapq.heappush(pq, (cost, v, src))

        # Grow tree until all destinations are reached
        while pq and len(reached.intersection(dsts)) < len(dsts):
            cost, node, parent = heapq.heappop(pq)
            if node in reached:
                continue

            # Add this node to tree
            reached.add(node)
            paths_to_dest[node] = paths_to_dest[parent] + [(parent, node)]

            # If this is a destination, record its path
            if node in dsts:
                path_edges = paths_to_dest[node]
                # Convert edge sequence to node path for topology
                node_path = [src]
                for (u, v) in path_edges:
                    if u == node_path[-1]:
                        node_path.append(v)
                # Add to topology
                for i in range(len(node_path) - 1):
                    s, t = node_path[i], node_path[i+1]
                    bc_topology.append_dst_partition_path(node, partition, [s, t, G[s][t]])

            # Add neighbors to queue
            for v in G_clean.neighbors(node):
                if v not in reached:
                    edge_cost = G_clean[node][v]['cost']
                    heapq.heappush(pq, (edge_cost, v, node))

        # For any unreached destination in this partition, use fallback
        for dst in dsts:
            if dst not in reached:
                path = fallback_paths[dst]
                if path:
                    for i in range(len(path) - 1):
                        s, t = path[i], path[i+1]
                        bc_topology.append_dst_partition_path(dst, partition, [s, t, G[s][t]])

    return bc_topology

import networkx as nx
from typing import List, Dict, Tuple
import heapq
from collections import defaultdict

def search_algorithm(src: str, dsts: List[str], G: nx.DiGraph, num_partitions: int) -> BroadCastTopology:
    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    # Precompute single-source shortest paths from source to all nodes
    try:
        pred, dist = nx.dijkstra_predecessor_and_distance(G, src, weight='cost')
    except nx.NetworkXNoPath:
        # If source is disconnected from any node, return empty topology
        return bc_topology

    # For each destination, compute k shortest simple paths using Yen's algorithm
    # with limited k to keep performance reasonable
    K = min(num_partitions, 5)  # Maximum distinct paths per destination

    dst_paths = {}
    for dst in dsts:
        if dst not in dist:
            dst_paths[dst] = []
            continue

        # Use Yen's algorithm to find K shortest paths
        try:
            # Start with the shortest path
            shortest_path = nx.dijkstra_path(G, src, dst, weight='cost')
            paths = [shortest_path]

            # Use a heap to store candidate paths
            candidates = []

            for k in range(1, K):
                # The spur node ranges from first to next-to-last node in the previous path
                for i in range(len(paths[k-1]) - 1):
                    spur_node = paths[k-1][i]
                    root_path = paths[k-1][:i+1]

                    # Create a temporary graph with edges from root_path removed
                    temp_G = G.copy()

                    # Remove edges that are part of previous paths' root_path segments
                    for path in paths:
                        if len(path) > i and path[:i+1] == root_path:
                            if temp_G.has_edge(path[i], path[i+1]):
                                temp_G.remove_edge(path[i], path[i+1])

                    # Remove nodes from root_path (except spur_node) to prevent cycles
                    for node in root_path[:-1]:
                        if node in temp_G:
                            temp_G.remove_node(node)

                    # Calculate spur path from spur_node to dst
                    try:
                        spur_path = nx.dijkstra_path(temp_G, spur_node, dst, weight='cost')

                        # Combine root_path and spur_path
                        total_path = root_path[:-1] + spur_path

