                    reuse += edge_usage[edge]

                # Prefer paths with higher edge reuse, but penalize high cost
                score = reuse - 0.01 * cost
                if score > best_reuse or (score == best_reuse and cost < best_cost):
                    best_reuse = score
                    best_cost = cost
