                subgraph_edges.append((u, v, data))

        # Use a greedy method to build a tree with minimum cost
        # This is a simplified version of minimum spanning tree concept
        tree_edges = set()
        visited = {src}
        priority_queue = []

        # Add all edges from source
        for u, v, data in subgraph_edges:
            if u == src and v not in visited:
                heapq.heappush(priority_queue, (data['cost'], u, v))

        # Kruskal-like approach for building tree
        while priority_queue and len(visited) < len(all_nodes_in_cloud):
            cost, u, v = heapq.heappop(priority_queue)
            if v not in visited:
                visited.add(v)
                tree_edges.add((u, v))
                # Add edges from new node
                for u2, v2, data in subgraph_edges:
                    if u2 == v and v2 not in visited:
                        heapq.heappush(priority_queue, (data['cost'], u2, v2))

        cloud_trees[cloud] = tree_edges

    # For each destination, assign partitions to optimized paths
    # Use a greedy assignment that tries to reuse edges efficiently
    edge_usage = defaultdict(list)

    # Assign partitions to paths for each destination
    for dst in dsts:
        # Direct path from source to destination
        if shortest_paths[dst] is None:
            continue

        path = shortest_paths[dst]

        # Assign each partition to this path
        for partition in range(num_partitions):
            # Determine which path segment to use for this partition
            # We'll assign to the direct path for now
            for i in range(len(path) - 1):
                u, v = path[i], path[i+1]
                if G.has_edge(u, v):
                    edge_usage[(u, v)].append((dst, partition))
                    bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])

    # Apply shared edge optimization: try to improve by reassigning partitions
    # This is done by checking if we can reduce the total cost with better sharing

    # Build a reverse mapping: from edge to partitions that use it
    edge_to_partitions = defaultdict(list)
    for (u, v), partitions in edge_usage.items():
        for dest, part in partitions:
            edge_to_partitions[(u, v)].append((dest, part))

    # Try to optimize edge sharing by reassigning partitions to reduce overall cost
    # This is a simple greedy improvement
    for dst in dsts:
        for partition in range(num_partitions):
            # Skip if already assigned
            assigned = False
            for edge, partitions in edge_usage.items():
                if (dst, partition) in partitions:
                    assigned = True
                    break

            if not assigned:
                # Find a cheaper path that hasn't been assigned yet
                try:
                    path = nx.dijkstra_path(G, src, dst, weight='cost')
                    for i in range(len(path) - 1):
                        u, v = path[i], path[i + 1]
                        if G.has_edge(u, v):
                            edge_usage[(u, v)].append((dst, partition))
                            bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])
                            break
                except nx.NetworkXNoPath:
                    pass

    return bc_topology

