from typing import List, Dict, Tuple


class BroadCastTopology:
    """Stores broadcast topology with paths for each (destination, partition) pair."""

    def __init__(self, src: str, dsts: List[str], num_partitions: int = 4, paths: Dict[str, Dict[str, List]] = None):
        self.src = src
        self.dsts = dsts
        self.num_partitions = num_partitions

        # dict(dst) -> dict(partition) -> list of edges
        if paths is not None:
            self.paths = paths
        else:
            self.paths = {dst: {str(i): None for i in range(num_partitions)} for dst in dsts}

    def get_paths(self):
        return self.paths

    def set_num_partitions(self, num_partitions: int):
        self.num_partitions = num_partitions

    def set_dst_partition_paths(self, dst: str, partition: int, paths: List):
        """Set paths for a specific partition to reach dst."""
        partition = str(partition)
        self.paths[dst][partition] = paths

    def append_dst_partition_path(self, dst: str, partition: int, path: List):
        """Append a path segment for a specific partition to reach dst."""
        partition = str(partition)
        if self.paths[dst][partition] is None:
            self.paths[dst][partition] = []
        self.paths[dst][partition].append(path)


def search_algorithm(src: str, dsts: List[str], G: nx.DiGraph, num_partitions: int) -> BroadCastTopology:
    # Preprocess graph to remove invalid edges
    h = G.copy()
    h.remove_edges_from(list(h.in_edges(src)) + list(nx.selfloop_edges(h)))

    # Precompute all shortest paths for each destination using cost as weight
    shortest_paths = {}
    for dst in dsts:
        if dst == src:
            continue
        try:
            path = nx.dijkstra_path(h, src, dst, weight='cost')
            shortest_paths[dst] = path
        except nx.NetworkXNoPath:
            shortest_paths[dst] = None

    # Initialize topology
    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    # For each destination, assign paths to partitions
    for dst in dsts:
        if dst == src or shortest_paths[dst] is None:
            continue

        path = shortest_paths[dst]
        # Create a mapping from path edges to their total cost
        path_edges = []
        for i in range(len(path) - 1):
            u, v = path[i], path[i + 1]
            path_edges.append((u, v, G[u][v]))

        # Distribute partitions along the path in a round-robin manner
        # Each edge in the path can carry multiple partitions
        for partition in range(num_partitions):
            # Assign path to partition
            for u, v, edge_data in path_edges:
                bc_topology.append_dst_partition_path(dst, partition, [u, v, edge_data])

    return bc_topology

