def search_algorithm(src: str, dsts: List[str], G: nx.DiGraph, num_partitions: int) -> BroadCastTopology:
    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    # Precompute shortest paths from source to all destinations
    shortest_paths = {}
    for dst in dsts:
        try:
            shortest_paths[dst] = nx.dijkstra_path(G, src, dst, weight='cost')
        except nx.NetworkXNoPath:
            shortest_paths[dst] = None

    # For each destination, find diverse paths considering edge usage
    # Use a greedy approach to distribute partitions among paths
    edge_usage = {}  # Track how many partitions use each edge

    for dst in dsts:
        if shortest_paths[dst] is None:
            continue

        path_list = []
        base_path = shortest_paths[dst]
        path_list.append(base_path)

        # Generate alternative paths by slightly modifying edge costs
        # to encourage diversity while keeping paths reasonable
        temp_G = G.copy()

        # Penalize edges already used in previous paths for this destination
        for edge, count in edge_usage.items():
            if temp_G.has_edge(*edge):
                temp_G[edge[0]][edge[1]]['cost'] *= (1.0 + count * 0.05)

        # Try to find alternative paths
        for i in range(min(3, num_partitions - 1)):
            try:
                alt_path = nx.dijkstra_path(temp_G, src, dst, weight='cost')
                if alt_path not in path_list:
                    path_list.append(alt_path)
                else:
                    # If path exists and we're looking for diversity,
                    # slightly penalize this edge to avoid repetition
                    if len(alt_path) > 1:
                        u, v = alt_path[-2], alt_path[-1]
                        if temp_G.has_edge(u, v):
                            temp_G[u][v]['cost'] *= 1.1
            except nx.NetworkXNoPath:
                break

        # Assign partitions to paths based on cost distribution
        path_costs = []
        for path in path_list:
            cost = sum(G[path[i]][path[i+1]]['cost'] for i in range(len(path)-1))
            path_costs.append(cost)

        # Normalize weights by inverse of cost
        total_inv_cost = sum(1.0 / (c + 0.001) for c in path_costs)
        if total_inv_cost > 0:
            weights = [(1.0 / (c + 0.001)) / total_inv_cost for c in path_costs]
        else:
            weights = [1.0 / len(path_costs)] * len(path_costs)

        # Assign partitions to paths in a way that balances load
        partition_assignments = []
        for i in range(num_partitions):
            # Use weighted assignment based on path costs
            assigned_idx = min(range(len(weights)), key=lambda x: sum(weights[x:] + weights[:x]) if x != 0 else sum(weights))
            partition_assignments.append(assigned_idx)

        # Distribute partitions according to assignment
        for partition in range(num_partitions):
            assigned_path_idx = partition_assignments[partition]
            path = path_list[assigned_path_idx]

            # Update edge usage and add to topology
            for i in range(len(path) - 1):
                u, v = path[i], path[i+1]
                edge_key = (u, v)
                edge_usage[edge_key] = edge_usage.get(edge_key, 0) + 1
                bc_topology.append_dst_partition_path(dst, partition, [u, v, G[u][v]])

    return bc_topology

