    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    # Precompute all-pairs shortest paths by cost for fallback
    all_shortest_paths = {}
    for dst in dsts:
        try:
            all_shortest_paths[dst] = nx.dijkstra_path(G, src, dst, weight='cost')
        except:
            all_shortest_paths[dst] = []

    # For each destination, find multiple good paths
    all_paths_per_dst = {}

    for dst in dsts:
        if dst == src:
            all_paths_per_dst[dst] = [[src]]
            continue

        paths = []

        # Get cheapest path first
        if all_shortest_paths[dst]:
            paths.append(all_shortest_paths[dst])

        # Try to find alternative paths with reasonable cost
        # Use a modified approach: find paths through different intermediate nodes

        # Get all nodes in the graph
        all_nodes = list(G.nodes())

        # Try using different intermediate hubs
        candidate_intermediates = []
        for node in all_nodes:
            if node != src and node != dst:
                try:
                    # Check if path exists through this node
                    path1 = nx.dijkstra_path(G, src, node, weight='cost')
                    path2 = nx.dijkstra_path(G, node, dst, weight='cost')
                    # Combine paths (remove duplicate node)
                    combined_path = path1 + path2[1:]
                    if combined_path not in paths:
                        paths.append(combined_path)
                        if len(paths) >= num_partitions:
                            break
                except:
                    continue

        # If still not enough paths, use k-shortest paths algorithm
        if len(paths) < num_partitions:
            try:
                k = min(num_partitions, 10)
                path_generator = nx.shortest_simple_paths(G, src, dst, weight='cost')
                for i, path in enumerate(path_generator):
                    if i >= k:
                        break
                    if path not in paths:
                        paths.append(path)
            except:
                pass

        all_paths_per_dst[dst] = paths

    # Assign partitions to minimize total cost
    # Simple strategy: assign each partition to the cheapest available path for each destination

    for dst in dsts:
        paths = all_paths_per_dst.get(dst, [])
        if not paths:
            # Fallback to any path
            try:
                path = nx.dijkstra_path(G, src, dst, weight='cost')
                paths = [path]
            except:
