            for i in range(len(path) - 1):
                cost += G[path[i]][path[i+1]]['cost']
            path_costs.append((cost, path))

        # Sort by cost
        path_costs.sort(key=lambda x: x[0])

        # Assign partitions in round-robin fashion, prioritizing cheaper paths
        for partition in range(num_partitions):
            if not path_costs:
                break

            # Use modulo to cycle through paths
            chosen_idx = partition % len(path_costs)
            chosen_path = path_costs[chosen_idx][1]

            # Add path to topology
            for i in range(len(chosen_path) - 1):
                s, t = chosen_path[i], chosen_path[i+1]
                bc_topology.append_dst_partition_path(dst, partition, [s, t, G[s][t]])

