    G_clean = G.copy()
    G_clean.remove_edges_from(list(G_clean.in_edges(src)) + list(nx.selfloop_edges(G_clean)))

    if not dsts:
        return bc_topology

    # Compute single-source shortest paths from source
    source_paths = {}
    for dst in dsts:
        try:
            path = nx.shortest_path(G_clean, src, dst, weight='cost')
            source_paths[dst] = path
        except nx.NetworkXNoPath:
            source_paths[dst] = []

    # Compute single-destination shortest paths (reverse graph)
    G_rev = G_clean.reverse(copy=True)
    dest_paths = {}
    for dst in dsts:
        try:
            path = nx.shortest_path(G_rev, dst, src, weight='cost')
            # Reverse to get path from src to dst
            path.reverse()
            dest_paths[dst] = path
        except nx.NetworkXNoPath:
            dest_paths[dst] = []

    # Find overlap between source and destination computed paths
    best_paths = {}
    for dst in dsts:
        src_path = source_paths[dst]
        dst_path = dest_paths[dst]

        # Prefer the path with lower actual cost
        if src_path and dst_path:
            src_cost = sum(G[u][v]['cost'] for u, v in zip(src_path[:-1], src_path[1:]))
            dst_cost = sum(G[u][v]['cost'] for u, v in zip(dst_path[:-1], dst_path[1:]))
            best_paths[dst] = src_path if src_cost <= dst_cost else dst_path
        elif src_path:
            best_paths[dst] = src_path
        elif dst_path:
            best_paths[dst] = dst_path
        else:
            best_paths[dst] = []

    # Find alternative paths by penalizing used edges
    all_paths = {dst: [] for dst in dsts}

    for dst in dsts:
        if not best_paths[dst]:
            continue

        temp_G = G_clean.copy()
        base_path = best_paths[dst]
        all_paths[dst].append(base_path)

        # Find alternative paths for partitions
        for alt_idx in range(min(num_partitions - 1, len(G_clean.nodes) // 2)):
            # Increase cost of edges in previously found paths
            for path in all_paths[dst]:
                for i in range(len(path) - 1):
                    u, v = path[i], path[i + 1]
                    if temp_G.has_edge(u, v):
                        temp_G[u][v]['cost'] *= 2.0

            try:
                alt_path = nx.shortest_path(temp_G, src, dst, weight='cost')
                if alt_path not in all_paths[dst]:
                    all_paths[dst].append(alt_path)
            except nx.NetworkXNoPath:
                break

        # Ensure we have at least one path
        if not all_paths[dst]:
            all_paths[dst] = [base_path]

    # Distribute partitions across available paths
    for dst in dsts:
        if not all_paths[dst]:
            continue

        paths = all_paths[dst]
        for partition in range(num_partitions):
            path_idx = partition % len(paths)
            path = paths[path_idx]

            for i in range(len(path) - 1):
                s, t = path[i], path[i + 1]
                bc_topology.append_dst_partition_path(dst, partition, [s, t, G[s][t]])

    return bc_topology
